def _client_demo_context():
    brand_id = session.get("client_brand_id")
    if not brand_id:
        return {"is_demo": False, "brand": {}}
    db = None
    try:
        db = _get_db()
        brand = db.get_brand(brand_id) or {}
    except Exception:
        brand = {}
    demo_session_id = int(brand.get("demo_session_id") or 0)
    demo_partner_id = int(brand.get("demo_partner_id") or 0)
    session_demo_id = int(session.get("client_demo_session_id") or 0)
    is_demo = False
    if db and demo_session_id and demo_partner_id:
        try:
            demo = db.get_partner_demo_session(demo_session_id, partner_id=demo_partner_id)
            is_demo = bool(demo and int(demo.get("demo_brand_id") or 0) == int(brand_id))
        except Exception:
            is_demo = False
    if is_demo and session.get("client_demo_mode") and session_demo_id and session_demo_id != demo_session_id:
        is_demo = False
    if not is_demo:
        session.pop("client_demo_mode", None)
        session.pop("client_demo_session_id", None)
        session.pop("client_demo_partner_id", None)
    return {"is_demo": is_demo, "brand": brand}


@client_bp.before_request
def _block_external_actions_in_demo_mode():
    if request.method not in {"POST", "PUT", "PATCH", "DELETE"}:
        return None
    if request.endpoint not in _DEMO_BLOCKED_ENDPOINTS:
        return None
    if not _client_demo_context()["is_demo"]:
        return None
    message = "Demo mode is active. WARREN kept this action inside the sandbox and did not send, publish, connect, bill, or push to an external system."
    wants_json = (
        request.path.startswith("/client/api/")
        or request.headers.get("X-Requested-With") in {"XMLHttpRequest", "PJAX"}
        or request.is_json
    )
    if wants_json:
        return jsonify({"ok": False, "demo_mode": True, "error": message}), 423
    flash(message, "warning")
    return redirect(request.referrer or url_for("client.client_auto_warren"))


def _require_role(*allowed_roles):
    current_role = str(session.get("client_role") or "owner").strip().lower()
    allowed = {
        str(role).strip().lower()
        for role in allowed_roles
        if str(role).strip()
    }
    if not allowed:
        return True
    return current_role in allowed


def _get_ad_connection_status(db, brand):
    brand_id = int((brand or {}).get("id") or 0)
    connections = db.get_brand_connections(brand_id) if brand_id else {}
    google_conn = connections.get("google", {}) if isinstance(connections, dict) else {}
    meta_conn = connections.get("meta", {}) if isinstance(connections, dict) else {}

    has_google = bool(
        google_conn.get("status") == "connected"
        and ((brand or {}).get("google_ads_customer_id") or "").strip()
    )
    has_meta = bool(meta_conn.get("status") == "connected")
    return has_google, has_meta


def _normalize_client_phone_number(value):
    phone = re.sub(r"[^\d+]", "", str(value or "").strip())
    if not phone:
        return ""
    if phone.startswith("+"):
        digits = "+" + re.sub(r"\D", "", phone[1:])
        return digits[:20]
    digits = re.sub(r"\D", "", phone)
    if len(digits) == 10:
        return f"+1{digits}"
    if len(digits) == 11 and digits.startswith("1"):
        return f"+{digits}"
    return f"+{digits}" if digits else ""


def _coerce_action_key(value, fallback):
    text = re.sub(r"[^a-z0-9]+", "_", (value or "").strip().lower()).strip("_")
    return (text or fallback)[:80]


def _safe_json_object(raw_value):
    if isinstance(raw_value, dict):
        return dict(raw_value)
    if not raw_value:
        return {}
    try:
        parsed = json.loads(raw_value)
    except Exception:
        return {}
    return dict(parsed) if isinstance(parsed, dict) else {}


def _safe_json_list(raw_value):
    if isinstance(raw_value, list):
        return list(raw_value)
    if not raw_value:
        return []
    try:
        parsed = json.loads(raw_value)
    except Exception:
        return []
    return list(parsed) if isinstance(parsed, list) else []


def _format_timestamp_for_timezone(raw_value, timezone_name):
    text = str(raw_value or "").strip()
    if not text:
        return ""

    # SQLite datetime('now') rows are UTC naive; treat naive values as UTC.
    normalized = text.replace("T", " ")
    if normalized.endswith("Z"):
        normalized = normalized[:-1] + "+00:00"
    if " " in normalized and "+" in normalized.rsplit(" ", 1)[-1] and "T" not in normalized:
        normalized = normalized.replace(" ", "T", 1)

    try:
        dt = datetime.fromisoformat(normalized)
    except Exception:
        return text[:16]

    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)

    try:
        from webapp.warren_appointments import _normalize_timezone_name, _get_zoneinfo

        zone_name = _normalize_timezone_name(timezone_name)
        zone = _get_zoneinfo(zone_name)
        return dt.astimezone(zone).strftime("%Y-%m-%d %H:%M")
    except Exception:
        return dt.astimezone(timezone.utc).strftime("%Y-%m-%d %H:%M")


def _maybe_run_due_appointment_check(db, brand_id, app_config):
    """If appointment reminders are due now, run a one-off check immediately after settings save."""
    brand = db.get_brand(brand_id)
    if not brand:
        return None
    if int(brand.get("sales_bot_appointment_reminders_enabled") or 0) != 1:
        return None

    try:
        from webapp.warren_appointments import _brand_local_now, _parse_send_minutes, process_appointment_reminders

        now_utc = datetime.now(timezone.utc)
        local_now = _brand_local_now(brand, now=now_utc)
        send_after_minutes = _parse_send_minutes(brand.get("sales_bot_appointment_reminder_send_time"))
        local_minutes = local_now.hour * 60 + local_now.minute
        if local_minutes < send_after_minutes:
            return None

        target_date = (local_now.date() + timedelta(days=1)).isoformat()
        recent_runs = db.get_appointment_reminder_runs(brand_id, limit=20)
        for run in recent_runs:
            if str(run.get("target_date") or "") == target_date and str(run.get("status") or "").strip().lower() in {
                "completed",
                "partial",
                "failed",
            }:
                return None

        return process_appointment_reminders(db, app_config, brand_ids=[brand_id])
    except Exception:
        return None


def _save_appointment_reminder_settings(db, brand_id, payload):
    valid_appointment_channels = {"email", "sms"}
    channels_raw = payload.get("sales_bot_appointment_reminder_channels")
    if isinstance(channels_raw, list):
        selected_appointment_channels = [c for c in channels_raw if c in valid_appointment_channels]
    else:
        selected_appointment_channels = []
    if not selected_appointment_channels:
        selected_appointment_channels = ["sms"]

    enabled_raw = payload.get("sales_bot_appointment_reminders_enabled")
    enabled = 1 if str(enabled_raw).strip().lower() in {"1", "true", "yes", "on"} else 0
    db.update_brand_number_field(brand_id, "sales_bot_appointment_reminders_enabled", enabled)

    send_time = (payload.get("sales_bot_appointment_reminder_send_time") or "17:00").strip()[:10]
    log.info(f"[Appointment] Saving send_time: {send_time} (from payload: {payload.get('sales_bot_appointment_reminder_send_time')})")
    db.update_brand_text_field(brand_id, "sales_bot_appointment_reminder_send_time", send_time)
    
    # Verify it was saved
    brand_check = db.get_brand(brand_id)
    log.info(f"[Appointment] Verified saved send_time: {brand_check.get('sales_bot_appointment_reminder_send_time')}")

    appointment_timezone = (payload.get("sales_bot_appointment_reminder_timezone") or "America/New_York").strip()
    if appointment_timezone not in {
        "America/New_York",
        "America/Chicago",
        "America/Denver",
        "America/Los_Angeles",
        "America/Anchorage",
        "Pacific/Honolulu",
    }:
        appointment_timezone = "America/New_York"
    db.update_brand_text_field(brand_id, "sales_bot_appointment_reminder_timezone", appointment_timezone)

    db.update_brand_text_field(brand_id, "sales_bot_appointment_reminder_channels", json.dumps(selected_appointment_channels))
    db.update_brand_number_field(
        brand_id,
        "sales_bot_appointment_reminder_respect_client_channel",
        1 if str(payload.get("sales_bot_appointment_reminder_respect_client_channel") or "").strip().lower() in {"1", "true", "yes", "on"} else 0,
    )
    db.update_brand_text_field(
        brand_id,
        "sales_bot_appointment_reminder_template",
        (payload.get("sales_bot_appointment_reminder_template") or "").strip()[:2000],
    )


def _save_payment_reminder_settings(db, brand_id, payload):
    valid_payment_channels = {"email", "sms"}
    channels_raw = payload.get("sales_bot_payment_reminder_channels")
    if isinstance(channels_raw, str):
        selected_payment_channels = [channels_raw] if channels_raw in valid_payment_channels else []
    else:
        selected_payment_channels = [c for c in (channels_raw or []) if c in valid_payment_channels]
    if not selected_payment_channels:
        selected_payment_channels = ["email"]

    db.update_brand_number_field(
        brand_id,
        "sales_bot_payment_reminders_enabled",
        1 if str(payload.get("sales_bot_payment_reminders_enabled") or "").strip().lower() in {"1", "true", "yes", "on"} else 0,
    )
    try:
        payment_days_before = max(0, min(21, int(float(payload.get("sales_bot_payment_reminder_days_before") or 3))))
    except (ValueError, TypeError):
        payment_days_before = 3
    db.update_brand_number_field(brand_id, "sales_bot_payment_reminder_days_before", payment_days_before)
    try:
        payment_billing_day = max(1, min(31, int(float(payload.get("sales_bot_payment_reminder_billing_day") or 1))))
    except (ValueError, TypeError):
        payment_billing_day = 1
    db.update_brand_number_field(brand_id, "sales_bot_payment_reminder_billing_day", payment_billing_day)
    db.update_brand_text_field(brand_id, "sales_bot_payment_reminder_channels", json.dumps(selected_payment_channels))
    db.update_brand_text_field(
        brand_id,
        "sales_bot_payment_reminder_template",
        (payload.get("sales_bot_payment_reminder_template") or "").strip()[:2000],
    )


def _normalize_site_builder_text(value, field_label, max_length=None, trim=True):
    if value is None:
        return ""
    if not isinstance(value, str):
        value = str(value)
    normalized = value.strip() if trim else value
    if max_length and len(normalized) > max_length:
        raise ValueError(f"{field_label} is too long.")
    return normalized


def _validate_site_builder_blob_size(value, field_label, max_bytes):
    size = len((value or "").encode("utf-8"))
    if size > max_bytes:
        raise ValueError(f"{field_label} is too large.")


def _normalize_site_builder_editor_json(raw_value):
    if raw_value in (None, ""):
        return ""
    if isinstance(raw_value, str):
        try:
            parsed = json.loads(raw_value)
        except Exception as exc:
            raise ValueError("Editor state is not valid JSON.") from exc
    else:
        parsed = raw_value
    try:
        normalized = json.dumps(parsed)
    except Exception as exc:
        raise ValueError("Editor state could not be serialized.") from exc
    _validate_site_builder_blob_size(normalized, "Editor state", _SITE_BUILDER_MAX_EDITOR_JSON_BYTES)
    return normalized


def _normalize_site_builder_page_save_payload(data):
    if data is None:
        return {}
    if not isinstance(data, dict):
        raise ValueError("Invalid page update payload.")

    update = {}
    if "content" in data:
        content = _normalize_site_builder_text(data.get("content"), "Page content", trim=False)
        _validate_site_builder_blob_size(content, "Page content", _SITE_BUILDER_MAX_CONTENT_BYTES)
        update["content"] = content
        update["full_html"] = content
    if "editor_json" in data:
        update["editor_json"] = _normalize_site_builder_editor_json(data.get("editor_json"))
    if "page_css" in data:
        page_css = _normalize_site_builder_text(data.get("page_css"), "Page CSS", trim=False)
        _validate_site_builder_blob_size(page_css, "Page CSS", _SITE_BUILDER_MAX_PAGE_CSS_BYTES)
        update["page_css"] = page_css
    if "seo_title" in data:
        update["seo_title"] = _normalize_site_builder_text(
            data.get("seo_title"),
            "SEO title",
            max_length=_SITE_BUILDER_MAX_SEO_TITLE_LENGTH,
        )
    if "seo_description" in data:
        update["seo_description"] = _normalize_site_builder_text(
            data.get("seo_description"),
            "SEO description",
            max_length=_SITE_BUILDER_MAX_SEO_DESCRIPTION_LENGTH,
        )
    if "title" in data:
        update["title"] = _normalize_site_builder_text(
            data.get("title"),
            "Page title",
            max_length=_SITE_BUILDER_MAX_TITLE_LENGTH,
        )
    return update


def _summarize_delivery_detail(raw_value):
    detail = _safe_json_object(raw_value)
    if not detail:
        text = str(raw_value or "").strip()
        return text[:160]

    result = detail.get("result")
    if isinstance(result, dict):
        status = str(result.get("status") or result.get("state") or result.get("type") or "").strip()
        message_id = str(result.get("id") or result.get("messageId") or result.get("message_id") or "").strip()
        if status and message_id:
            return f"{status} - {message_id}"[:160]
        if status:
            return status[:160]
        if message_id:
            return f"Message ID {message_id}"[:160]
        rendered = json.dumps(result, separators=(",", ":"))
        return rendered[:160]

    if result:
        return str(result)[:160]
    if detail.get("error"):
        return str(detail.get("error"))[:160]
    rendered = json.dumps(detail, separators=(",", ":"))
    return rendered[:160]


def _split_text_lines(value, limit=24):
    parts = []
    seen = set()
    for raw_part in re.split(r"[\n,;|]+", str(value or "")):
        item = re.sub(r"\s+", " ", raw_part).strip()
        if not item:
            continue
        lowered = item.lower()
        if lowered in seen:
            continue
        seen.add(lowered)
        parts.append(item[:120])
        if len(parts) >= limit:
            break
    return parts


def _default_lead_form_service_options(brand):
    options = _split_text_lines((brand or {}).get("primary_services") or "")
    if options:
        return options
    options = _split_text_lines((brand or {}).get("sales_bot_service_menu") or "")
    cleaned = []
    for option in options:
        cleaned.append(re.sub(r"^[-*\d.)\s]+", "", option).strip())
        if len(cleaned) >= 8:
            break
    return [item for item in cleaned if item]


