def _extract_drive_download_file_id(image_url):
    parsed = urlparse((image_url or "").strip())
    path = parsed.path or (image_url or "").strip()
    match = re.match(r"^/client/api/drive/download/([A-Za-z0-9_-]+)$", path)
    return match.group(1) if match else ""


def _resolve_scheduler_image_url(image_url, brand_id):
    cleaned = (image_url or "").strip()
    if not cleaned:
        return ""
    file_id = _extract_drive_download_file_id(cleaned)
    if file_id:
        return _build_public_drive_download_url(brand_id, file_id)
    return cleaned


def _normalize_scheduled_datetime(raw_value):
    raw = (raw_value or "").strip()
    if not raw:
        return None

    for fmt in (
        "%Y-%m-%dT%H:%M",
        "%Y-%m-%dT%H:%M:%S",
        "%Y-%m-%d %H:%M",
        "%Y-%m-%d %H:%M:%S",
    ):
        try:
            parsed = datetime.strptime(raw, fmt)
            return parsed.strftime("%Y-%m-%d %H:%M:%S")
        except ValueError:
            continue

    try:
        parsed = datetime.fromisoformat(raw)
    except ValueError:
        return None
    return parsed.strftime("%Y-%m-%d %H:%M:%S")


def _parse_scheduler_datetime_to_utc(raw_value, timezone_name="", timezone_offset_minutes=None):
    raw = str(raw_value or "").strip()
    if not raw:
        return None

    normalized = raw.replace(" ", "T")
    try:
        parsed = datetime.fromisoformat(normalized)
    except ValueError:
        return None

    if parsed.tzinfo is not None:
        return parsed.astimezone(timezone.utc)

    tz = None
    if timezone_name:
        try:
            from webapp.warren_appointments import _normalize_timezone_name, _get_zoneinfo

            tz = _get_zoneinfo(_normalize_timezone_name(timezone_name))
        except Exception:
            tz = None

    if tz is None and timezone_offset_minutes is not None:
        try:
            offset = int(timezone_offset_minutes)
            tz = timezone(timedelta(minutes=-offset))
        except Exception:
            tz = None

    if tz is None:
        tz = timezone.utc

    return parsed.replace(tzinfo=tz).astimezone(timezone.utc)


def _format_facebook_proof_timestamp(value):
    raw = str(value or "").strip()
    if not raw:
        return ""
    try:
        cleaned = raw.replace("Z", "+00:00")
        if re.search(r"[+-]\d{4}$", cleaned):
            cleaned = f"{cleaned[:-5]}{cleaned[-5:-2]}:{cleaned[-2:]}"
        parsed = datetime.fromisoformat(cleaned)
        return parsed.strftime("%Y-%m-%d %H:%M:%S")
    except ValueError:
        return raw.replace("T", " ")[:19]


def _maybe_post_facebook_first_comment(db, post, page_token):
    first_comment = _format_facebook_first_comment(post.get("first_comment") or "")
    if not first_comment:
        return
    status = str(post.get("first_comment_status") or "").strip().lower()
    if status == "posted":
        return
    fb_post_id = str(post.get("fb_post_id") or "").strip()
    if not fb_post_id:
        return

    try:
        import requests as req_lib
        resp = req_lib.post(
            f"https://graph.facebook.com/v21.0/{fb_post_id}/comments",
            data={"access_token": page_token, "message": first_comment},
            timeout=20,
        )
        payload = resp.json() if resp.content else {}
        comment_id = str((payload or {}).get("id") or "").strip()
        if resp.status_code == 200 and comment_id:
            db.update_scheduled_post_first_comment(post["id"], "posted", comment_id=comment_id)
            post["first_comment_status"] = "posted"
            post["first_comment_id"] = comment_id
        else:
            error_msg = ((payload or {}).get("error") or {}).get("message") or resp.text[:300]
            db.update_scheduled_post_first_comment(post["id"], "failed", error_message=error_msg[:300])
            post["first_comment_status"] = "failed"
            post["first_comment_error"] = error_msg[:300]
    except Exception as exc:
        db.update_scheduled_post_first_comment(post["id"], "failed", error_message=str(exc)[:300])
        post["first_comment_status"] = "failed"
        post["first_comment_error"] = str(exc)[:300]


def _load_facebook_published_post_proof(db, brand, brand_id, posts, limit=12):
    page_id = str((brand or {}).get("facebook_page_id") or "").strip()
    candidates = [post for post in posts or [] if str(post.get("fb_post_id") or "").strip()]
    if not page_id or not candidates:
        return []

    try:
        from webapp.api_bridge import _get_meta_token, _get_page_access_token
        import requests as req_lib

        connections = db.get_brand_connections(brand_id)
        meta_conn = connections.get("meta")
        if not meta_conn or meta_conn.get("status") != "connected":
            return []
        user_token = _get_meta_token(db, brand_id, meta_conn)
        if not user_token:
            return []
        page_token = _get_page_access_token(page_id, user_token)
        if not page_token:
            return []

        proofs = []
        for post in candidates[: max(limit * 2, limit)]:
            fb_post_id = str(post.get("fb_post_id") or "").strip()
            if not fb_post_id:
                continue

            try:
                resp = req_lib.get(
                    f"https://graph.facebook.com/v21.0/{fb_post_id}",
                    params={
                        "access_token": page_token,
                        "fields": "id,permalink_url,created_time,message",
                    },
                    timeout=15,
                )
            except Exception:
                continue

            if resp.status_code != 200:
                continue
            payload = resp.json() or {}
            if payload.get("error"):
                continue

            permalink_url = str(payload.get("permalink_url") or "").strip()
            if not permalink_url:
                continue

            published_at = _format_facebook_proof_timestamp(payload.get("created_time") or post.get("published_at") or post.get("scheduled_at"))
            post["proof_url"] = permalink_url
            post["published_at"] = published_at or post.get("published_at") or ""
            if post.get("status") != "published":
                db.update_scheduled_post_status(post["id"], "published", fb_post_id=fb_post_id)
                post["status"] = "published"
            _maybe_post_facebook_first_comment(db, post, page_token)

            proofs.append(
                {
                    "id": post.get("id"),
                    "post_type_label": post.get("post_type_label") or _facebook_post_type_label(post.get("post_type")),
                    "message": (payload.get("message") or post.get("message") or "")[:280],
                    "permalink_url": permalink_url,
                    "published_at": published_at,
                    "fb_post_id": fb_post_id,
                    "proof_url": permalink_url,
                }
            )
            if len(proofs) >= limit:
                break
        return proofs
    except Exception:
        current_app.logger.exception("scheduler published proof lookup failed for brand %s", brand_id)
        return []


def _warm_client_snapshots_async(*, brand_id: int, month: str) -> None:
    """Warm heavy caches in the background after login.

    Populates:
    - analysis + suggestions (monthly_summary)
    - campaigns list snapshot (settings)
    - full dashboard snapshot (dashboard_snapshots table)

    Best-effort: failures should never block the request.
    """

    try:
        app = current_app._get_current_object()
    except Exception:
        return

        # Adding outreach deletion confirmation
        flash("Commercial outreach deleted.", "success")
    def _runner():
        try:
            with app.app_context():
                db = getattr(app, "db", None)
                if not db:
                    return
                brand = db.get_brand(brand_id)
                if not brand:
                    return

                analysis = None
                suggestions = None
                try:
                    from webapp.report_runner import get_analysis_and_suggestions_for_brand

                    analysis, suggestions = get_analysis_and_suggestions_for_brand(
                        db, brand, month, force_refresh=True
                    )
                except Exception as exc:
                    log.info("Warm-up analysis failed (brand=%s month=%s): %s", brand_id, month, exc)

                campaigns_data = {}
                try:
                    campaigns_data = _get_campaigns_cached(db, brand, month, force_sync=True)
                except Exception as exc:
                    log.info("Warm-up campaigns failed (brand=%s month=%s): %s", brand_id, month, exc)

                # Build and save full dashboard snapshot
                if analysis:
                    try:
                        dashboard_data = _assemble_dashboard_payload(
                            db, brand, brand_id, month, analysis, suggestions, campaigns_data
                        )
                        db.upsert_dashboard_snapshot(
                            brand_id, month,
                            json.dumps(dashboard_data, default=str),
                            source="warmup",
                        )
                    except Exception as exc:
                        log.info("Warm-up snapshot save failed (brand=%s): %s", brand_id, exc)
        except Exception:
            return

    try:
        t = threading.Thread(target=_runner, name=f"warmup-{brand_id}-{month}", daemon=True)
        t.start()
    except Exception:
        return


def _assemble_dashboard_payload(db, brand, brand_id, month, analysis, suggestions, campaigns_data):
    """Build the full dashboard JSON payload from pre-fetched data.

    Shared by the /dashboard/data endpoint and the warm-up thread so the
    snapshot contains the exact same structure the frontend expects.
    """
    from webapp.client_advisor import build_client_dashboard

    dashboard_data = build_client_dashboard(analysis, suggestions, brand)

    # Store raw analysis in snapshot so missions can regenerate from it later
    dashboard_data["_snapshot_version"] = _DASHBOARD_SNAPSHOT_VERSION
    dashboard_data["_analysis"] = analysis
    dashboard_data["_suggestions"] = suggestions

    dashboard_data["campaigns"] = {
        "google": [
            {
                "id": c.get("id", ""),
                "name": c.get("name", ""),
                "status": c.get("status", ""),
                "daily_budget": c.get("daily_budget", 0),
                "spend": c.get("spend", 0),
                "clicks": c.get("clicks", 0),
                "ctr": c.get("ctr", 0),
                "conversions": c.get("conversions", 0),
                "cpa": c.get("cpa", 0),
                "channel_type": c.get("channel_type", ""),
            }
            for c in (campaigns_data.get("google") or [])
        ],
        "meta": [
            {
                "id": c.get("id", ""),
                "name": c.get("name", ""),
                "status": c.get("status", ""),
                "daily_budget": c.get("daily_budget", 0),
                "spend": c.get("spend", 0),
                "clicks": c.get("clicks", 0),
                "ctr": c.get("ctr", 0),
                "conversions": c.get("conversions", 0),
                "cpa": c.get("cpa", 0),
                "objective": c.get("objective", ""),
            }
            for c in (campaigns_data.get("meta") or [])
        ],
    }

    try:
        dashboard_data["target_cpa"] = float(brand.get("kpi_target_cpa") or 0)
    except (ValueError, TypeError):
        dashboard_data["target_cpa"] = 0.0

    try:
        drafts_raw = db.get_campaign_drafts(brand_id) or []
        dashboard_data["drafts"] = [
            {
                "id": dr["id"],
                "platform": dr.get("platform", ""),
                "campaign_name": dr.get("campaign_name", "Untitled"),
                "status": dr.get("status", "draft"),
                "created_by": dr.get("created_by", ""),
                "updated_at": dr.get("updated_at", dr.get("created_at", "")),
            }
            for dr in drafts_raw
        ]
    except Exception:
        dashboard_data["drafts"] = []

    try:
        if brand.get("crm_type") == "sweepandgo" and brand.get("crm_api_key"):
            from webapp.crm_bridge import (
                sng_count_active_clients,
                sng_count_happy_clients,
                sng_count_happy_dogs,
                sng_count_jobs,
            )
            dashboard_data["sng"] = {
                "connected": True,
                "active_clients": sng_count_active_clients(brand) or 0,
                "happy_clients": sng_count_happy_clients(brand) or 0,
                "happy_dogs": sng_count_happy_dogs(brand) or 0,
                "completed_jobs": sng_count_jobs(brand) or 0,
            }
    except Exception:
        dashboard_data["sng"] = {"connected": False}

    try:
        latest_findings = db.get_agent_findings(brand_id, month=month, limit=50)
        briefing_critical = [f for f in latest_findings if f.get("severity") == "critical"]
        briefing_warning = [f for f in latest_findings if f.get("severity") == "warning"]
        briefing_positive = [f for f in latest_findings if f.get("severity") == "positive"]

        dashboard_data["warren_briefing"] = {
            "total_findings": len(latest_findings),
            "critical_count": len(briefing_critical),
            "warning_count": len(briefing_warning),
            "positive_count": len(briefing_positive),
            "top_critical": [
                {"title": f.get("title", ""), "detail": f.get("detail", ""), "agent": f.get("agent_key", "")}
                for f in briefing_critical[:3]
            ],
            "top_warnings": [
                {"title": f.get("title", ""), "detail": f.get("detail", ""), "agent": f.get("agent_key", "")}
                for f in briefing_warning[:3]
            ],
            "top_wins": [
                {"title": f.get("title", ""), "detail": f.get("detail", ""), "agent": f.get("agent_key", "")}
                for f in briefing_positive[:3]
            ],
        }
    except Exception:
        dashboard_data["warren_briefing"] = None

    try:
        hired_agents = json.loads(brand.get("hired_agents") or "{}")
        active_count = len([a for a in hired_agents.values() if a.get("trained")])
        dashboard_data["team_status"] = {
            "hired": len(hired_agents),
            "trained": active_count,
            "total_available": len(AGENT_ROSTER),
        }
    except Exception:
        dashboard_data["team_status"] = None

    dashboard_data = _attach_owner_engagement(db, brand, brand_id, month, dashboard_data)
    return dashboard_data


