def _serialize_heatmap_scan(scan, include_results=False):
    from webapp.heatmap import summarize_competitor_landscape

    if not scan:
        return None
    payload = dict(scan)
    payload["status"] = payload.get("status") or "complete"
    payload["error_message"] = payload.get("error_message") or ""
    try:
        payload["debug"] = json.loads(payload.get("debug_json") or "{}")
    except Exception:
        payload["debug"] = {}
    if include_results:
        try:
            payload["results"] = json.loads(payload.get("results_json") or "[]")
        except Exception:
            payload["results"] = []
        payload["competitor_summary"] = summarize_competitor_landscape(payload["results"])
    return payload


def _finalize_heatmap_scan(*, keyword, api_key, business_name, grid_points, place_id,
                           search_radius, alternate_names, brand_query, place_verification,
                           business_lat, business_lng, keyword_warning, keyword_was_cleaned,
                           target_place_ids=None, local_falcon_api_key="", grid_size=None,
                           radius_miles=None, center_lat=None, center_lng=None):
    from webapp.heatmap import (
        scan_grid_google_rank_only,
        scan_grid_local_falcon_saved_report,
        summarize_competitor_landscape,
    )

    try:
        local_falcon_error = None
        local_falcon_report_miss = None
        if local_falcon_api_key:
            try:
                results, debug_info = scan_grid_local_falcon_saved_report(
                    local_falcon_api_key,
                    keyword,
                    place_id,
                    grid_size or int(len(grid_points) ** 0.5),
                    target_place_ids=target_place_ids,
                    candidate_names=[business_name, *(alternate_names or [])],
                )
                if results is None:
                    local_falcon_report_miss = (
                        ((debug_info or {}).get("api_diagnostics") or {})
                        .get("local_falcon_saved_report", {})
                        .get("error")
                    ) or "No saved Local Falcon scan report matched this scan."
                else:
                    debug_info = debug_info or {}
                    debug_info["local_falcon_source"] = "saved_report"
            except Exception as exc:
                local_falcon_error = str(exc)
                current_app.logger.warning("Local Falcon saved report lookup failed: %s", exc)

            if local_falcon_report_miss:
                local_falcon_error = local_falcon_report_miss

        if not local_falcon_api_key or local_falcon_error:
            results, debug_info = scan_grid_google_rank_only(
                api_key,
                keyword,
                business_name,
                grid_points,
                place_id=place_id,
                search_radius_m=search_radius,
                alternate_names=alternate_names,
                brand_query=brand_query,
                target_place_ids=target_place_ids,
            )
            if local_falcon_error or local_falcon_report_miss:
                debug_info = debug_info or {}
                diagnostics = debug_info.setdefault("api_diagnostics", {})
                if local_falcon_report_miss:
                    diagnostics["local_falcon_saved_report"] = {
                        "provider": "local_falcon_saved_report",
                        "ok": False,
                        "error": local_falcon_report_miss,
                        "fallback": "google_rank_only",
                    }
                diagnostics["local_falcon"] = {
                    "provider": "local_falcon",
                    "ok": False,
                    "error": local_falcon_error or local_falcon_report_miss,
                    "fallback": "google_rank_only",
                }
                debug_info["local_falcon_error"] = local_falcon_error or local_falcon_report_miss
                debug_info["local_falcon_fallback"] = "Google rank-only scan used because Local Falcon failed."
    except Exception as exc:
        raise RuntimeError(f"Scan failed: {exc}") from exc

    if debug_info and place_verification:
        debug_info["place_id_verification"] = place_verification
        pv_lat = place_verification.get("lat")
        pv_lng = place_verification.get("lng")
        if pv_lat is not None and pv_lng is not None:
            import math as _math
            dlat = abs(pv_lat - business_lat)
            dlng = abs(pv_lng - business_lng)
            dist_km = _math.sqrt(dlat**2 + dlng**2) * 111.32
            place_verification["distance_from_center_km"] = round(dist_km, 1)
            if dist_km > 50:
                place_verification["location_warning"] = (
                    f"Place ID location is {round(dist_km)}km from your stored business location. "
                    "This may be the wrong listing. Try re-searching your Place ID."
                )

    if debug_info and keyword_warning:
        debug_info["keyword_warning"] = keyword_warning
    if keyword_was_cleaned and debug_info:
        near_me_note = (
            'Stripped "near me" from your keyword (the API already receives your '
            'exact coordinates and search radius, so "near me" is redundant and '
            'can reduce result count).'
        )
        if debug_info.get("keyword_warning"):
            debug_info["keyword_warning"] += " " + near_me_note
        else:
            debug_info["keyword_warning"] = near_me_note

    ranked = [r for r in results if r["rank"] > 0]
    avg_rank = round(sum(r["rank"] for r in ranked) / len(ranked), 1) if ranked else 0
    competitor_summary = summarize_competitor_landscape(results)

    return {
        "keyword": keyword,
        "results": results,
        "avg_rank": avg_rank,
        "found": len(ranked),
        "total": len(results),
        "competitor_summary": competitor_summary,
        "debug": debug_info,
    }


def _run_heatmap_scan_job(app, brand_id, scan_id, scan_kwargs):
    with app.app_context():
        db = app.db
        try:
            payload = _finalize_heatmap_scan(**scan_kwargs)
            db.update_heatmap_scan(
                scan_id,
                brand_id,
                results_json=json.dumps(payload["results"]),
                avg_rank=payload["avg_rank"],
                status="complete",
                error_message="",
                debug_json=json.dumps(payload.get("debug") or {}),
            )
        except Exception as exc:
            db.update_heatmap_scan(
                scan_id,
                brand_id,
                status="failed",
                error_message=str(exc)[:2000],
                debug_json=json.dumps({"error": str(exc)}),
            )


def _start_heatmap_scan_job(app, brand_id, scan_id, scan_kwargs):
    thread = threading.Thread(
        target=_run_heatmap_scan_job,
        args=(app, brand_id, scan_id, scan_kwargs),
        daemon=True,
    )
    thread.start()


def _resolve_brand_maps_api_key(db, brand):
    if not brand:
        return ""
    return (
        brand.get("google_maps_api_key")
        or os.environ.get("GOOGLE_MAPS_API_KEY")
        or db.get_setting("google_maps_api_key")
        or ""
    ).strip()


def _resolve_local_falcon_api_key(db, brand=None):
    brand = brand or {}
    return (
        brand.get("local_falcon_api_key")
        or os.environ.get("LOCAL_FALCON_API_KEY")
        or db.get_setting("local_falcon_api_key")
        or db.get_setting("localfalcon_api_key")
        or ""
    ).strip()


def _hydrate_heatmap_brand(db, brand):
    if not brand:
        return None

    hydrated = dict(brand)
    hydrated["google_maps_api_key"] = _resolve_brand_maps_api_key(db, hydrated)

    business_lat = float(hydrated.get("business_lat") or 0)
    business_lng = float(hydrated.get("business_lng") or 0)
    place_id = (hydrated.get("google_place_id") or "").strip()
    api_key = hydrated.get("google_maps_api_key", "")

    if (business_lat != 0 or business_lng != 0) or not place_id or not api_key:
        return hydrated

    try:
        from webapp.heatmap import verify_place_id

        verified = verify_place_id(api_key, place_id) or {}
        verified_lat = verified.get("lat")
        verified_lng = verified.get("lng")
        if verified_lat is None or verified_lng is None:
            return hydrated

        verified_lat = float(verified_lat)
        verified_lng = float(verified_lng)
        db.update_brand_number_field(hydrated["id"], "business_lat", verified_lat)
        db.update_brand_number_field(hydrated["id"], "business_lng", verified_lng)
        hydrated["business_lat"] = verified_lat
        hydrated["business_lng"] = verified_lng
    except Exception:
        pass

    return hydrated


def _load_heatmap_state(db, brand_id, scan_limit=20):
    brand = db.get_brand(brand_id)
    if not brand:
        return None, [], None
    brand = _hydrate_heatmap_brand(db, brand)

    scans = db.get_heatmap_scans(brand_id, limit=scan_limit)
    active_scan = _serialize_heatmap_scan(scans[0], include_results=True) if scans else None
    return brand, scans, active_scan


def _next_heatmap_run_at(day_of_week, run_time, timezone_name, now_utc=None):
    try:
        day_of_week = max(0, min(6, int(day_of_week)))
    except (TypeError, ValueError):
        day_of_week = 0

    run_time = (run_time or "08:00").strip()
    if not re.match(r"^\d{2}:\d{2}$", run_time):
        run_time = "08:00"
    hour, minute = [int(part) for part in run_time.split(":", 1)]
    hour = max(0, min(23, hour))
    minute = max(0, min(59, minute))

    tz = timezone.utc
    if ZoneInfo:
        try:
            tz = ZoneInfo(timezone_name or "America/Phoenix")
        except Exception:
            tz = ZoneInfo("America/Phoenix")

    now_utc = now_utc or datetime.now(timezone.utc)
    now_local = now_utc.astimezone(tz)
    days_ahead = (day_of_week - now_local.weekday()) % 7
    candidate = (now_local + timedelta(days=days_ahead)).replace(
        hour=hour,
        minute=minute,
        second=0,
        microsecond=0,
    )
    if candidate <= now_local:
        candidate += timedelta(days=7)
    return candidate.astimezone(timezone.utc).strftime("%Y-%m-%d %H:%M:%S")


def _prepare_heatmap_scan_kwargs(db, brand, *, keyword, radius_miles=5, grid_size=5,
                                 center_lat=None, center_lng=None, provider_preference="auto"):
    if not brand:
        return None, "Brand not found"
    brand = _hydrate_heatmap_brand(db, brand)

    try:
        radius = float(radius_miles or 5)
    except (TypeError, ValueError):
        radius = 5.0
    radius = max(1.0, min(50.0, radius))

    try:
        grid_size = int(grid_size or 5)
    except (TypeError, ValueError):
        grid_size = 5
    grid_size = max(3, min(10, grid_size))

    keyword = (keyword or "").strip()
    if not keyword:
        return None, "Keyword is required"

    api_key = _resolve_brand_maps_api_key(db, brand)
    if not api_key:
        return None, "Google Maps API key not configured. Add it in Connections."

    business_lat = float(brand.get("business_lat") or 0)
    business_lng = float(brand.get("business_lng") or 0)
    if business_lat == 0 and business_lng == 0:
        return None, "Business location not set. Set your address on the heatmap page first."

    try:
        scan_center_lat = float(center_lat) if center_lat is not None else business_lat
        scan_center_lng = float(center_lng) if center_lng is not None else business_lng
    except (TypeError, ValueError):
        return None, "Scan center coordinates are invalid."

    if not (-90 <= scan_center_lat <= 90) or not (-180 <= scan_center_lng <= 180):
        return None, "Scan center coordinates are out of range."

    from webapp.heatmap import generate_grid, calc_search_radius_m, verify_place_id, clean_keyword

    grid_points = generate_grid(scan_center_lat, scan_center_lng, radius, grid_size)
    search_radius = calc_search_radius_m(radius, grid_size)
    business_name = brand.get("display_name", "")
    place_id = brand.get("google_place_id") or None
    if not place_id:
        return None, "Google Place ID is required for rank-only heatmap scans. Link the correct listing first."

    keyword, keyword_was_cleaned = clean_keyword(keyword)

    place_verification = verify_place_id(api_key, place_id)
    alternate_names = []
    verified_name = ((place_verification or {}).get("name") or "").strip()
    if verified_name and verified_name.lower() != business_name.lower().strip():
        alternate_names.append(verified_name)
    if not business_name and verified_name:
        business_name = verified_name

    listing_names = [business_name, *alternate_names]
    keyword_brand_query = False
    kw_lower = keyword.lower().strip()
    for listing_name in listing_names:
        normalized_listing_name = (listing_name or "").lower().strip()
        if normalized_listing_name and (kw_lower == normalized_listing_name or kw_lower in normalized_listing_name or normalized_listing_name in kw_lower):
            keyword_brand_query = True
            break

    keyword_warning = None
    bn_lower = business_name.lower().strip()
    if bn_lower and (kw_lower == bn_lower or kw_lower in bn_lower or bn_lower in kw_lower):
        keyword_warning = (
            "You searched your business name. The heatmap is designed for "
            "service keywords, the terms customers use to find businesses like yours. "
            "Try keywords like \"pooper scooper\", \"dog poop cleanup\", etc. "
            "That shows where you rank vs. competitors when people search for your service."
        )

    provider_preference = (provider_preference or "auto").strip().lower()
    if provider_preference not in {"auto", "google", "local_falcon"}:
        provider_preference = "auto"
    local_falcon_api_key = ""
    if provider_preference in {"auto", "local_falcon"}:
        local_falcon_api_key = _resolve_local_falcon_api_key(db, brand)

    return {
        "keyword": keyword,
        "api_key": api_key,
        "local_falcon_api_key": local_falcon_api_key,
        "business_name": business_name,
        "grid_points": grid_points,
        "place_id": place_id,
        "target_place_ids": [place_id] if place_id else [],
        "search_radius": search_radius,
        "grid_size": grid_size,
        "radius_miles": radius,
        "center_lat": scan_center_lat,
        "center_lng": scan_center_lng,
        "alternate_names": alternate_names,
        "brand_query": keyword_brand_query,
        "place_verification": place_verification,
        "business_lat": business_lat,
        "business_lng": business_lng,
        "keyword_warning": keyword_warning,
        "keyword_was_cleaned": keyword_was_cleaned,
    }, None


