def _clean_font_display_name(value, fallback):
    raw = (value or fallback or "Uploaded Font").rsplit(".", 1)[0].strip()
    cleaned = re.sub(r"[^A-Za-z0-9 _.-]+", "", raw).strip(" ._-")
    return (cleaned or "Uploaded Font")[:80]


