def _configured_ai_providers(brand):
    brand = brand or {}
    providers = []
    provider_fields = {
        "openai": "openai_api_key",
        "openrouter": "ai_openrouter_api_key",
        "gemini": "ai_gemini_api_key",
        "xai": "ai_xai_api_key",
        "bfl": "ai_bfl_api_key",
        "custom": "ai_custom_api_key",
    }
    for provider, field in provider_fields.items():
        if (brand.get(field) or "").strip():
            providers.append(provider)
    return providers


def _ai_recommendations_for_brand(brand):
    configured = set(_configured_ai_providers(brand))
    rows = []
    for provider, suggestions in _AI_TEXT_MODEL_RECOMMENDATIONS.items():
        if provider == "bfl":
            continue
        if provider in configured or provider == (brand or {}).get("ai_provider"):
            rows.append({"provider": provider, "suggestions": suggestions})
    if not rows:
        rows.append({"provider": "openai", "suggestions": _AI_TEXT_MODEL_RECOMMENDATIONS["openai"]})
    return rows


def _image_model_options_for_provider(provider):
    return _IMAGE_MODEL_OPTIONS.get(provider) or _IMAGE_MODEL_OPTIONS["openai"]


def _image_creator_prompt(
    brand,
    user_prompt,
    style,
    format_key,
    include_brand_context=True,
    asset_type="basic_visual",
    tone="professional",
    text_sections=None,
    custom_instructions="",
    tool_references=None,
):
    fmt = _IMAGE_CREATOR_FORMATS.get(format_key, _IMAGE_CREATOR_FORMATS["square"])
    text_sections = text_sections or {}
    asset_labels = {
        "basic_visual": "a clean visual asset with no readable text",
        "full_ad": "a finished advertising image with only the provided text",
        "social_graphic": "a social media graphic",
        "website_hero": "a website hero image",
        "service_proof": "a service proof or before/after-style visual",
        "custom": "a custom marketing image",
    }
    parts = [
        f"Create a polished marketing image for {brand.get('display_name') or 'this business'}.",
        f"Asset type: {asset_labels.get(asset_type, asset_labels['basic_visual'])}.",
        f"Format: {fmt['hint']}.",
        f"Creative direction: {user_prompt}.",
        f"Visual style: {style or 'clean, practical, professional'}.",
        f"Tone: {tone or 'professional'}.",
        "Avoid text-heavy layouts, distorted hands, illegible signage, watermarks, logos from other brands, and generic stock-photo composition.",
    ]
    if asset_type == "full_ad":
        allowed_text = [(label, (text_sections.get(label) or "").strip()) for label in ("headline", "subheadline", "offer", "cta", "fine_print")]
        allowed_text = [(label, value) for label, value in allowed_text if value]
        if allowed_text:
            parts.append("This is a finished ad image. Include ONLY these exact text strings, with no extra words, misspellings, invented phone numbers, URLs, badges, or labels:")
            for label, value in allowed_text:
                parts.append(f"- {label.replace('_', ' ').title()}: {value}")
            parts.append("If the model cannot render text perfectly, prioritize clean layout and leave uncertain text out rather than inventing or altering words.")
        else:
            parts.append("This is an ad-style image, but no exact text was provided. Do not render readable text.")
    else:
        parts.append("Do not render readable text unless exact text sections are provided.")
    if custom_instructions:
        parts.append(f"Custom production notes: {custom_instructions}")
    tool_references = tool_references or []
    if tool_references:
        parts.append(
            "Tool accuracy references: Use these brand-approved tools and usage examples when any tool, equipment, worker, or service action appears. "
            "Do not substitute generic shovels, garden rakes, trash grabbers, janitorial carts, or unrelated equipment unless the reference explicitly says so."
        )
        for item in tool_references[:8]:
            name = (item.get("tool_name") or "Approved tool").strip()
            category = (item.get("category") or "tool").replace("_", " ")
            description = (item.get("description") or "").strip()
            usage_notes = (item.get("usage_notes") or "").strip()
            line = f"- {name} ({category})"
            if description:
                line += f": {description}"
            if usage_notes:
                line += f" Usage: {usage_notes}"
            parts.append(line[:360])
    if include_brand_context:
        context_bits = []
        for label, field in (
            ("Industry", "industry"),
            ("Services", "primary_services"),
            ("Service area", "service_area"),
            ("Brand voice", "brand_voice"),
            ("Colors", "brand_colors"),
        ):
            value = (brand.get(field) or "").strip()
            if value:
                context_bits.append(f"{label}: {value}")
        if context_bits:
            parts.append("Brand context: " + "; ".join(context_bits[:5]) + ".")
    return "\n".join(parts)


def _normalize_qr_color(value, fallback):
    value = (value or "").strip()
    if re.match(r"^#[0-9a-fA-F]{6}$", value):
        return value.lower()
    return fallback


def _normalize_tracking_url(raw_url):
    value = (raw_url or "").strip()
    if not value:
        return ""
    if not re.match(r"^https?://", value, re.IGNORECASE):
        value = "https://" + value
    parsed = urlparse(value)
    if parsed.scheme not in ("http", "https") or not parsed.netloc:
        return ""
    return value


def _qr_tracking_url(tracking_slug):
    return url_for("client_public.public_qr_redirect", tracking_slug=tracking_slug, _external=True)


def _new_qr_tracking_slug(db):
    for _ in range(12):
        slug = secrets.token_urlsafe(8).replace("-", "").replace("_", "")[:10]
        if not db.get_qr_code_by_slug(slug):
            return slug
    return secrets.token_urlsafe(12).replace("-", "").replace("_", "")[:16]


def _hash_qr_ip(ip_value):
    secret = current_app.config.get("SECRET_KEY") or os.environ.get("SECRET_KEY") or "warren"
    return hashlib.sha256(f"{secret}:{ip_value or ''}".encode("utf-8")).hexdigest()[:32]


def _make_plain_qr_image(qr_record, tracking_url, size):
    import qrcode
    from PIL import Image

    foreground = _normalize_qr_color(qr_record.get("foreground_color"), "#111827")
    background = _normalize_qr_color(qr_record.get("background_color"), "#ffffff")
    qr = qrcode.QRCode(
        version=None,
        error_correction=qrcode.constants.ERROR_CORRECT_H,
        box_size=18,
        border=4,
    )
    qr.add_data(tracking_url)
    qr.make(fit=True)
    qr_img = qr.make_image(fill_color=foreground, back_color=background).convert("RGB")
    return qr_img.resize((size, size), Image.Resampling.NEAREST)


def _render_branded_qr_png(qr_record, tracking_url, brand):
    qr_img = _make_plain_qr_image(qr_record, tracking_url, 900)

    out = BytesIO()
    qr_img.save(out, format="PNG")
    out.seek(0)
    return out


