def _test_generic_integration(provider, config):
    provider = (provider or "").strip().lower()
    config = config or {}
    timeout = 12
    try:
        if provider == "callrail":
            account_id = (config.get("account_id") or "").strip()
            api_key = (config.get("api_key") or "").strip()
            if not account_id or not api_key:
                return False, "CallRail account ID and API key are required."
            resp = requests.get(
                f"https://api.callrail.com/v3/a/{account_id}/companies.json",
                headers={"Authorization": f"Token token={api_key}", "Accept": "application/json"},
                timeout=timeout,
            )
            if resp.status_code != 200:
                return False, f"CallRail returned {resp.status_code}: {resp.text[:180]}"
            return True, "Connected to CallRail."

        if provider == "calendly":
            token = (config.get("api_key") or "").strip()
            if not token:
                return False, "Calendly personal access token is required."
            resp = requests.get(
                "https://api.calendly.com/users/me",
                headers={"Authorization": f"Bearer {token}", "Accept": "application/json"},
                timeout=timeout,
            )
            if resp.status_code != 200:
                return False, f"Calendly returned {resp.status_code}: {resp.text[:180]}"
            data = resp.json() or {}
            name = ((data.get("resource") or {}).get("name") or "").strip()
            return True, f"Connected to Calendly{f' as {name}' if name else ''}."

        if provider == "mailchimp":
            api_key = (config.get("api_key") or "").strip()
            if "-" not in api_key:
                return False, "Mailchimp API key must include the data center suffix, like us21."
            dc = api_key.rsplit("-", 1)[-1]
            resp = requests.get(
                f"https://{dc}.api.mailchimp.com/3.0/ping",
                auth=("gromore", api_key),
                timeout=timeout,
            )
            if resp.status_code != 200:
                return False, f"Mailchimp returned {resp.status_code}: {resp.text[:180]}"
            return True, "Connected to Mailchimp."

        if provider == "twilio":
            sid = (config.get("account_sid") or "").strip()
            token = (config.get("auth_token") or "").strip()
            if not sid or not token:
                return False, "Twilio Account SID and auth token are required."
            resp = requests.get(
                f"https://api.twilio.com/2010-04-01/Accounts/{sid}.json",
                auth=(sid, token),
                timeout=timeout,
            )
            if resp.status_code != 200:
                return False, f"Twilio returned {resp.status_code}: {resp.text[:180]}"
            return True, "Connected to Twilio."

        if provider == "quickbooks":
            realm_id = (config.get("realm_id") or "").strip()
            token = (config.get("access_token") or "").strip()
            if not realm_id or not token:
                return False, "QuickBooks realm ID and access token are required for a live test."
            resp = requests.get(
                f"https://quickbooks.api.intuit.com/v3/company/{realm_id}/companyinfo/{realm_id}",
                headers={"Authorization": f"Bearer {token}", "Accept": "application/json"},
                timeout=timeout,
            )
            if resp.status_code != 200:
                return False, f"QuickBooks returned {resp.status_code}: {resp.text[:180]}"
            return True, "Connected to QuickBooks Online."

        if provider == "housecallpro":
            api_key = (config.get("api_key") or "").strip()
            if not api_key:
                return False, "Housecall Pro API key is required."
            resp = requests.get(
                "https://api.housecallpro.com/customers?limit=1",
                headers={"Authorization": f"Bearer {api_key}", "Accept": "application/json"},
                timeout=timeout,
            )
            if resp.status_code != 200:
                return False, f"Housecall Pro returned {resp.status_code}: {resp.text[:180]}"
            return True, "Connected to Housecall Pro."

        if provider in ("zapier", "make"):
            webhook_url = (config.get("webhook_url") or "").strip()
            if not webhook_url:
                return False, "Webhook URL is required."
            resp = requests.post(
                webhook_url,
                json={"source": "gromore", "event": "connection_test", "sent_at": datetime.utcnow().isoformat()},
                timeout=timeout,
            )
            if resp.status_code not in (200, 201, 202, 204):
                return False, f"Webhook returned {resp.status_code}: {resp.text[:180]}"
            return True, "Webhook accepted the test event."

        if provider == "teamup_calendar":
            from webapp.teamup_calendar import teamup_test_connection

            return teamup_test_connection(config)
    except requests.RequestException as exc:
        return False, f"Network error: {str(exc)[:180]}"
    except Exception as exc:
        return False, f"Test failed: {str(exc)[:180]}"

    return False, "Live API test is not implemented for this provider yet."


@client_bp.route("/settings")
@client_login_required
def client_settings():
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
    if not brand:
        abort(404)
    client_user = db.get_client_user(session.get("client_user_id"))

    connections = db.get_brand_connections(brand_id)
    integration_configs = db.get_brand_integration_configs(brand_id)
    integration_catalog = _prepared_integration_catalog(integration_configs)
    from webapp.connection_health import evaluate_brand_connection_health

    connection_health = evaluate_brand_connection_health(db, brand, persist=True)
    for item in connection_health:
        item["status_badge"] = {
            "ok": "success",
            "warn": "warning text-dark",
            "fail": "danger",
            "info": "secondary",
        }.get((item.get("status") or "info").strip().lower(), "secondary")
    google_conn = connections.get("google", {})
    meta_conn = connections.get("meta", {})
    scopes = (google_conn.get("scopes") or "").lower()
    # Check for full 'auth/drive' scope (not just drive.file)
    has_full_drive = "auth/drive " in (scopes + " ") or scopes.endswith("auth/drive")
    drive_scoped = has_full_drive or ("spreadsheets" in scopes)
    try:
        chatbot_channels = set(json.loads(brand.get("sales_bot_channels") or "[]"))
    except Exception:
        chatbot_channels = set()

    def _brand_has_value(field_name):
        return bool((brand.get(field_name) or "").strip())

    warren_channel_readiness = {
        "sms": (
            _brand_has_value("quo_api_key")
            and _brand_has_value("quo_phone_number")
            and _brand_has_value("sales_bot_quo_webhook_secret")
        ),
        "lead_forms": _brand_has_value("sales_bot_incoming_webhook_secret"),
        "messenger": bool(meta_conn.get("status") == "connected" and _brand_has_value("facebook_page_id")),
    }
    warren_ready_count = sum(1 for is_ready in warren_channel_readiness.values() if is_ready)
    warren_total_count = len(warren_channel_readiness)
    if warren_ready_count == warren_total_count and warren_total_count:
        warren_status_state = "ready"
    elif warren_ready_count:
        warren_status_state = "partial"
    else:
        warren_status_state = "not_configured"

    try:
        sng_secret = db.ensure_brand_sng_webhook_secret(brand_id)
        sng_webhook_url = f"{_external_app_url()}{url_for('webhooks.sng_webhook', brand_slug=brand['slug'], secret=sng_secret)}"

        sng_webhook_events = db.get_sng_webhook_events(brand_id, limit=10)
        for event in sng_webhook_events:
            event["summary"] = _safe_json_object(event.get("summary_json"))
            event["status_badge"] = {
                "received": "success",
                "processed": "primary",
                "ignored": "secondary",
                "failed": "danger",
            }.get((event.get("status") or "").strip().lower(), "secondary")
        lead_webhook_deliveries = db.get_lead_webhook_deliveries(brand_id, limit=10)
        for delivery in lead_webhook_deliveries:
            delivery["status_badge"] = {
                "accepted": "success",
                "rejected": "danger",
            }.get((delivery.get("status") or "").strip().lower(), "secondary")
        crm_push_deliveries = db.get_crm_push_deliveries(brand_id, limit=10)
        for delivery in crm_push_deliveries:
            delivery["status_badge"] = {
                "delivered": "success",
                "failed": "danger",
                "skipped": "secondary",
                "pending": "warning",
            }.get((delivery.get("status") or "").strip().lower(), "secondary")
            delivery["can_retry"] = (delivery.get("status") or "").strip().lower() == "failed"

        square_oauth_configured = bool(
            (current_app.config.get("SQUARE_APP_ID") or "").strip()
            and (current_app.config.get("SQUARE_APP_SECRET") or "").strip()
        )

        return render_template(
            "client_connections.html",
            brand=brand,
            client_user=client_user,
            google_connected=(google_conn.get("status") == "connected"),
            meta_connected=(meta_conn.get("status") == "connected"),
            drive_scoped=drive_scoped,
            chatbot_channels=chatbot_channels,
            google_conn=google_conn,
            meta_conn=meta_conn,
            integration_catalog=integration_catalog,
            integration_connected_count=sum(1 for item in integration_catalog if item.get("is_configured")),
            connection_health=connection_health,
            warren_channel_readiness=warren_channel_readiness,
            warren_ready_count=warren_ready_count,
            warren_total_count=warren_total_count,
            warren_status_state=warren_status_state,
            sng_webhook_url=sng_webhook_url,
            jobber_oauth_callback_url=_jobber_oauth_callback_url(),
            jobber_webhook_url=_jobber_webhook_url(brand),
            square_oauth_callback_url=_square_oauth_callback_url(),
            square_webhook_url=_square_webhook_url(brand),
            teamup_webhook_url=f"{_external_app_url()}{url_for('webhooks.teamup_calendar_webhook', brand_slug=brand['slug'])}",
            square_oauth_configured=square_oauth_configured,
            sng_webhook_events=sng_webhook_events,
            lead_webhook_deliveries=lead_webhook_deliveries,
            crm_push_deliveries=crm_push_deliveries,
            ai_model_recommendations=_ai_recommendations_for_brand(brand),
            image_model_options_by_provider=_IMAGE_MODEL_OPTIONS,
            brand_name=session.get("client_brand_name", brand.get("display_name", "")),
        )
    except Exception:
        current_app.logger.exception("client_settings render error for brand %s", brand_id)
        flash("Settings page failed to load. The error has been logged.", "error")
        return redirect(url_for("client.client_dashboard"))


@client_bp.route("/settings/password", methods=["POST"])
@client_login_required
def client_change_password():
    db = _get_db()
    client_user_id = session.get("client_user_id")
    client_user = db.get_client_user(client_user_id)
    if not client_user or int(client_user.get("brand_id") or 0) != int(session.get("client_brand_id") or 0):
        session.pop("client_user_id", None)
        session.pop("client_brand_id", None)
        session.pop("client_name", None)
        session.pop("client_brand_name", None)
        flash("Your session expired. Sign in again to update your password.", "error")
        return redirect(url_for("client.client_login"))

    current_password = request.form.get("current_password", "")
    new_password = request.form.get("new_password", "")
    confirm_password = request.form.get("confirm_password", "")

    if not db.authenticate_client(client_user.get("email") or "", current_password):
        flash("Current password is incorrect.", "error")
        return redirect(url_for("client.client_settings"))

    password_error = _validate_client_password(new_password, confirm_password)
    if password_error:
        flash(password_error, "error")
        return redirect(url_for("client.client_settings"))

    db.update_client_user_password(client_user_id, new_password)
    flash("Password updated.", "success")
    return redirect(url_for("client.client_settings"))


@client_bp.route("/settings/email-identity", methods=["POST"])
@client_login_required
def client_save_email_identity():
    db = _get_db()
    brand_id = session["client_brand_id"]

    sender_name = (request.form.get("email_sender_name") or "").replace("\r", " ").replace("\n", " ").strip()[:120]
    reply_to = (request.form.get("email_reply_to") or "").replace("\r", " ").replace("\n", " ").strip().lower()[:255]

    if reply_to and not re.match(r"^[^@\s]+@[^@\s]+\.[^@\s]+$", reply_to):
        flash("Reply-to email needs to be a valid email address.", "error")
        return redirect(url_for("client.client_settings") + "#connection-panel-email")

    db.update_brand_text_field(brand_id, "email_sender_name", sender_name)
    db.update_brand_text_field(brand_id, "email_reply_to", reply_to)

    flash("Email sender identity saved.", "success")
    return redirect(url_for("client.client_settings") + "#connection-panel-email")


def _load_client_automation_context(db, brand_id):
    chatbot_channels = set()
    brand = db.get_brand(brand_id) or {}
    from webapp.warren_crm_events import RULE_DEFINITIONS, load_crm_event_rules

    try:
        chatbot_channels = set(json.loads(brand.get("sales_bot_channels") or "[]"))
    except Exception:
        chatbot_channels = set()

    appointment_tz = (brand.get("sales_bot_appointment_reminder_timezone") or "America/New_York").strip() or "America/New_York"
    appointment_last_attempt_display = _format_timestamp_for_timezone(
        brand.get("sales_bot_appointment_reminder_last_attempt_at"),
        appointment_tz,
    )

    appointment_runs = db.get_appointment_reminder_runs(brand_id, limit=8, min_sent=1)
    for run in appointment_runs:
        summary = _safe_json_object(run.get("summary_json"))
        run["summary"] = summary
        run["created_at_display"] = _format_timestamp_for_timezone(run.get("created_at"), appointment_tz)
        run["status_badge"] = {
            "completed": "success",
            "partial": "warning",
            "failed": "danger",
            "waiting": "secondary",
            "config_error": "danger",
        }.get((run.get("status") or "").strip().lower(), "secondary")

    appointment_attempts = db.get_brand_client_billing_reminders(
        brand_id,
        reminder_type="appointment_day_ahead",
        limit=20,
    )
    for attempt in appointment_attempts:
        attempt["detail_data"] = _safe_json_object(attempt.get("detail"))
        attempt["detail_summary"] = _summarize_delivery_detail(attempt.get("detail"))
        attempt["updated_at_display"] = _format_timestamp_for_timezone(attempt.get("updated_at"), appointment_tz)

    billing_attempts = db.get_brand_client_billing_reminders(
        brand_id,
        reminder_type="payment_due",
        limit=25,
    )
    for attempt in billing_attempts:
        attempt["detail_data"] = _safe_json_object(attempt.get("detail"))
        attempt["detail_summary"] = _summarize_delivery_detail(attempt.get("detail"))
        attempt["client_label"] = attempt["detail_data"].get("client_name") or attempt.get("external_client_id") or "Client"
        attempt["updated_at_display"] = _format_timestamp_for_timezone(attempt.get("updated_at"), appointment_tz)
        attempt["status_badge"] = {
            "sent": "success",
            "failed": "danger",
            "pending": "secondary",
        }.get((attempt.get("status") or "").strip().lower(), "secondary")

    sng_webhook_events = db.get_sng_webhook_events(brand_id, limit=10)
    for event in sng_webhook_events:
        event["summary"] = _safe_json_object(event.get("summary_json"))
        event["status_badge"] = {
            "received": "success",
            "processed": "primary",
            "ignored": "secondary",
            "failed": "danger",
        }.get((event.get("status") or "").strip().lower(), "secondary")

    crm_event_rules = load_crm_event_rules(brand)
    crm_event_actions = db.get_crm_event_actions(brand_id, limit=20)
    for action in crm_event_actions:
        action["status_badge"] = {
            "queued": "secondary",
            "sent": "success",
            "failed": "danger",
            "resolved": "primary",
        }.get((action.get("status") or "").strip().lower(), "secondary")
        action["rule_label"] = RULE_DEFINITIONS.get(action.get("rule_key"), {}).get("label", (action.get("rule_key") or "").replace("_", " ").title())

    return {
        "brand": brand,
        "chatbot_channels": chatbot_channels,
        "appointment_reminder_last_attempt_display": appointment_last_attempt_display,
        "appointment_reminder_runs": appointment_runs,
        "appointment_reminder_attempts": appointment_attempts,
        "billing_reminder_attempts": billing_attempts,
        "sng_webhook_events": sng_webhook_events,
        "crm_event_rules": crm_event_rules,
        "crm_event_actions": crm_event_actions,
        "crm_event_rule_definitions": RULE_DEFINITIONS,
    }


@client_bp.route("/automations")
@client_login_required
def client_automations():
    db = _get_db()
    brand_id = session["client_brand_id"]
