@client_bp.route("/settings/openai", methods=["POST"])
@client_login_required
def client_save_openai():
    from webapp.ai_provider import normalize_provider

    db = _get_db()
    brand_id = session["client_brand_id"]

    provider = normalize_provider(request.form.get("ai_provider", "openai"))
    image_provider = normalize_provider(request.form.get("ai_image_provider", "openai"))
    custom_base_url = request.form.get("ai_provider_base_url", "").strip().rstrip("/")
    image_generation_model = request.form.get("ai_image_generation_model", "").strip()
    quality_tier = request.form.get("ai_quality_tier", "").strip().lower()
    seo_provider = (request.form.get("seo_research_provider") or "openrouter").strip().lower()
    if seo_provider not in {"openrouter", "perplexity", "off"}:
        seo_provider = "openrouter"
    seo_enabled = "1" if request.form.get("seo_research_enabled") else "0"
    token_fields = {
        "openai_api_key": request.form.get("openai_api_key", "").strip(),
        "ai_openrouter_api_key": request.form.get("ai_openrouter_api_key", "").strip(),
        "ai_gemini_api_key": request.form.get("ai_gemini_api_key", "").strip(),
        "ai_xai_api_key": request.form.get("ai_xai_api_key", "").strip(),
        "ai_bfl_api_key": request.form.get("ai_bfl_api_key", "").strip(),
        "ai_custom_api_key": request.form.get("ai_custom_api_key", "").strip(),
        "seo_perplexity_api_key": request.form.get("seo_perplexity_api_key", "").strip(),
    }

    # Save quality tier
    if quality_tier in ("efficient", "balanced", "premium"):
        db.update_brand_text_field(brand_id, "ai_quality_tier", quality_tier)

        # Quality tiers are OpenAI presets. Non-OpenAI providers keep owner-entered model IDs.
        if provider == "openai":
            _tier_map = {
                "efficient": {"openai_model": "gpt-4o-mini", "openai_model_chat": "gpt-4o-mini", "openai_model_images": "gpt-4o-mini", "openai_model_analysis": "gpt-4o-mini", "openai_model_ads": "gpt-4o-mini"},
                "balanced":  {"openai_model": "gpt-4o-mini", "openai_model_chat": "gpt-4o-mini", "openai_model_images": "gpt-4o",      "openai_model_analysis": "gpt-4o-mini", "openai_model_ads": "gpt-4o"},
                "premium":   {"openai_model": "gpt-4.1",     "openai_model_chat": "gpt-4.1",     "openai_model_images": "gpt-4o",      "openai_model_analysis": "gpt-4.1",     "openai_model_ads": "gpt-4.1"},
            }
            for field, model_val in _tier_map[quality_tier].items():
                db.update_brand_text_field(brand_id, field, model_val)

    if provider in ("openrouter", "gemini", "xai", "custom"):
        for field in ("openai_model_chat", "openai_model_analysis", "openai_model_ads"):
            value = request.form.get(field, "").strip()[:120]
            if value:
                db.update_brand_text_field(brand_id, field, value)

    known_image_defaults = set(_IMAGE_PROVIDER_DEFAULT_MODELS.values()) | {"dall-e-3", "gpt-image-1"}
    if image_generation_model in known_image_defaults and image_generation_model != _IMAGE_PROVIDER_DEFAULT_MODELS.get(image_provider, ""):
        image_generation_model = ""
    db.update_brand_text_field(brand_id, "ai_image_generation_model", image_generation_model[:120])

    for field, token in token_fields.items():
        if not token:
            continue
        if field == "openai_api_key" and not token.startswith("sk-"):
            flash("Invalid API key format. OpenAI keys start with sk-", "error")
            return redirect(url_for("client.client_settings"))
        db.update_brand_text_field(brand_id, field, token)

    # Keep the legacy single provider field populated for older call sites.
    legacy_provider_token = {
        "openrouter": token_fields["ai_openrouter_api_key"],
        "gemini": token_fields["ai_gemini_api_key"],
        "xai": token_fields["ai_xai_api_key"],
        "bfl": token_fields["ai_bfl_api_key"],
        "custom": token_fields["ai_custom_api_key"],
    }.get(provider, "")
    if legacy_provider_token:
        db.update_brand_text_field(brand_id, "ai_provider_api_key", legacy_provider_token)

    if provider == "custom":
        if custom_base_url:
            if not _valid_custom_ai_base_url(custom_base_url):
                flash("Custom AI base URL must be a public HTTPS endpoint.", "error")
                return redirect(url_for("client.client_settings"))
            db.update_brand_text_field(brand_id, "ai_provider_base_url", custom_base_url)
    elif provider == "openrouter":
        db.update_brand_text_field(brand_id, "ai_provider_base_url", "https://openrouter.ai/api/v1")

    db.update_brand_text_field(brand_id, "ai_provider", provider)
    if image_provider in {"openai", "gemini", "xai", "bfl"}:
        db.update_brand_text_field(brand_id, "ai_image_provider", image_provider)

    db.update_brand_text_field(brand_id, "seo_research_enabled", seo_enabled)
    db.update_brand_text_field(brand_id, "seo_research_provider", seo_provider)
    db.update_brand_text_field(
        brand_id,
        "seo_research_model",
        (request.form.get("seo_research_model") or "perplexity/sonar").strip()[:120],
    )
    for field, default, minimum, maximum in (
        ("seo_research_daily_limit", 5, 0, 100),
        ("seo_research_cache_days", 14, 1, 90),
        ("seo_research_max_results", 8, 3, 20),
    ):
        try:
            value = int(float((request.form.get(field) or str(default)).strip()))
        except Exception:
            value = default
        db.update_brand_text_field(brand_id, field, str(max(minimum, min(maximum, value))))

    flash("AI settings saved.", "success")
    return_to = request.form.get("return_to")
    return redirect(url_for("client.client_connections") if return_to == "connections" else url_for("client.client_settings"))


@client_bp.route("/seo/research", methods=["POST"])
@client_login_required
def client_seo_research():
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
    if not brand:
        return jsonify(ok=False, error="Brand not found"), 404

    data = request.get_json(silent=True) or {}
    query = (data.get("query") or "").strip()[:500]
    force = bool(data.get("force"))

    seo_data = {}
    try:
        gsc_url = (brand.get("gsc_site_url") or "").strip()
        if gsc_url:
            from datetime import datetime, timedelta

            from src.api_search_console import pull_search_console_data

            today = datetime.utcnow()
            first_of_month = today.replace(day=1)
            last_month = first_of_month - timedelta(days=1)
            month_str = last_month.strftime("%Y-%m")
            oauth_tokens = None
            google_conn = (db.get_brand_connections(brand_id).get("google") or {})
            if google_conn.get("access_token"):
                oauth_tokens = {
                    "access_token": google_conn["access_token"],
                    "refresh_token": google_conn.get("refresh_token", ""),
                    "client_id": (db.get_setting("google_client_id", "") or current_app.config.get("GOOGLE_CLIENT_ID", "")).strip(),
                    "client_secret": (db.get_setting("google_client_secret", "") or current_app.config.get("GOOGLE_CLIENT_SECRET", "")).strip(),
                }
            seo_data = pull_search_console_data(gsc_url, month_str, oauth_tokens=oauth_tokens) or {}
    except Exception as exc:
        current_app.logger.warning("SEO research Search Console context failed: %s", exc)

    try:
        from webapp.seo_research import run_seo_research

        result = run_seo_research(db, brand, seo_data=seo_data, query=query, force=force)
        status = 200 if result.get("ok") else 400
        return jsonify(result), status
    except Exception as exc:
        current_app.logger.exception("SEO research failed for brand %s", brand_id)
        return jsonify(ok=False, error=str(exc)[:300]), 500


