@client_bp.route("/reviews/send", methods=["POST"])
@client_login_required
def client_reviews_send():
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
    if not brand:
        abort(404)

    groups = request.form.getlist("groups")
    channels = request.form.getlist("channels")
    manual = {
        "name": request.form.get("manual_name") or "",
        "email": request.form.get("manual_email") or "",
        "phone": request.form.get("manual_phone") or "",
    }
    use_manual = bool((manual["email"] or manual["phone"]).strip())
    if request.form.get("confirm_send") != "1":
        flash("Confirm the review request before sending.", "warning")
        return redirect(url_for("client.client_reviews"))

    try:
        from webapp.review_collector import send_review_requests

        if groups:
            db.update_brand_text_field(brand_id, "review_default_group_keys", json.dumps(groups))
        result = send_review_requests(
            db,
            current_app.config,
            brand,
            group_keys=groups,
            channels=channels,
            manual_recipient=manual if use_manual else None,
            created_by=session.get("client_name") or session.get("client_email") or "client",
        )
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(url_for("client.client_reviews"))
    except Exception as exc:
        log.exception("Review request send failed for brand %s", brand_id)
        flash(f"Review request failed: {exc}", "error")
        return redirect(url_for("client.client_reviews"))

    pieces = []
    if "sms" in channels:
        pieces.append(f"{result['sent_sms']} SMS")
    if "email" in channels:
        pieces.append(f"{result['sent_email']} email")
    suffix = f"; {result['skipped']} skipped" if result.get("skipped") else ""
    if result.get("failed"):
        suffix += f"; {result['failed']} failed"
    flash(f"Review requests sent to {result['recipient_count']} recipient(s): {', '.join(pieces)}{suffix}.", "success")
    return redirect(url_for("client.client_reviews"))


@client_bp.route("/reviews/automation/run", methods=["POST"])
@client_login_required
def client_reviews_run_automation():
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
    if not brand:
        abort(404)
    try:
        from webapp.review_collector import process_review_automation

        result = process_review_automation(
            db,
            current_app.config,
            brand,
            created_by=session.get("client_name") or "automation",
        )
    except ValueError as exc:
        flash(str(exc), "warning")
        return redirect(url_for("client.client_reviews"))
    except Exception as exc:
        log.exception("Review automation failed for brand %s", brand_id)
        flash(f"Review automation failed: {exc}", "error")
        return redirect(url_for("client.client_reviews"))
    if not result.get("ran"):
        flash(result.get("reason") or "Review automation did not run.", "warning")
        return redirect(url_for("client.client_reviews"))
    session["review_sweep_result"] = {
        "checked": result.get("checked", 0),
        "eligible": result.get("eligible", 0),
        "suppressed": result.get("suppressed", 0),
        "suppressed_counts": result.get("suppressed_counts") or {},
        "sent_sms": result.get("sent_sms", 0),
        "sent_email": result.get("sent_email", 0),
        "failed": result.get("failed", 0),
        "crm_service_lookups": result.get("crm_service_lookups", 0),
        "crm_service_matches": result.get("crm_service_matches", 0),
        "crm_service_warnings": result.get("crm_service_warnings") or [],
        "errors": result.get("errors") or {},
        "reason": result.get("reason") or "",
        "sent": bool(result.get("sent")),
    }
    if not result.get("sent"):
        counts = result.get("suppressed_counts") or {}
        top_reasons = ", ".join(
            f"{key.replace('_', ' ')}: {value}" for key, value in sorted(counts.items(), key=lambda item: item[1], reverse=True)[:3]
        )
        detail = f" Top blockers: {top_reasons}." if top_reasons else ""
        reason = f" {result.get('reason')}" if result.get("reason") else ""
        flash(
            f"Audience sweep checked {result.get('checked', 0)} recipient(s). "
            f"{result.get('suppressed', 0)} suppressed, 0 sent. "
            f"CRM service lookups matched {result.get('crm_service_matches', 0)} recent date(s).{detail}{reason}",
            "warning",
        )
        return redirect(url_for("client.client_reviews"))
    flash(
        f"Audience sweep checked {result.get('checked', 0)} recipient(s), found {result.get('eligible', 0)} eligible, "
        f"matched {result.get('crm_service_matches', 0)} recent CRM service date(s), "
        f"and sent {result.get('sent_sms', 0)} SMS plus {result.get('sent_email', 0)} email request(s).",
        "success",
    )
    return redirect(url_for("client.client_reviews"))


