@client_bp.route("/heatmap/scan", methods=["POST"])
@client_login_required
def client_heatmap_scan():
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
    if not brand:
        return jsonify(ok=False, error="Brand not found"), 404

    data = request.get_json(silent=True) or {}
    scan_kwargs, error = _prepare_heatmap_scan_kwargs(
        db,
        brand,
        keyword=data.get("keyword"),
        radius_miles=data.get("radius_miles") or 5,
        grid_size=data.get("grid_size") or 6,
        center_lat=data.get("center_lat"),
        center_lng=data.get("center_lng"),
        provider_preference=data.get("provider_preference") or "auto",
    )
    if error:
        return jsonify(ok=False, error=error), 400

    keyword = scan_kwargs["keyword"]
    grid_size = scan_kwargs["grid_size"]
    radius = scan_kwargs["radius_miles"]
    scan_center_lat = scan_kwargs["center_lat"]
    scan_center_lng = scan_kwargs["center_lng"]
    grid_points = scan_kwargs["grid_points"]

    if len(grid_points) > _HEATMAP_ASYNC_POINT_THRESHOLD:
        scan_id = db.save_heatmap_scan(
            brand_id,
            keyword,
            grid_size,
            radius,
            scan_center_lat,
            scan_center_lng,
            "[]",
            0,
            status="pending",
            debug_json=json.dumps({"status": "pending"}),
        )
        _start_heatmap_scan_job(current_app._get_current_object(), brand_id, scan_id, scan_kwargs)
        return jsonify(
            ok=True,
            pending=True,
            status="pending",
            scan_id=scan_id,
            keyword=keyword,
            center_lat=scan_center_lat,
            center_lng=scan_center_lng,
        )

    payload = _finalize_heatmap_scan(**scan_kwargs)
    scan_id = db.save_heatmap_scan(
        brand_id,
        keyword,
        grid_size,
        radius,
        scan_center_lat,
        scan_center_lng,
        json.dumps(payload["results"]),
        payload["avg_rank"],
        status="complete",
        debug_json=json.dumps(payload.get("debug") or {}),
    )

    return jsonify(
        ok=True,
        pending=False,
        status="complete",
        results=payload["results"],
        avg_rank=payload["avg_rank"],
        found=payload["found"],
        total=payload["total"],
        competitor_summary=payload["competitor_summary"],
        scan_id=scan_id,
        center_lat=scan_center_lat,
        center_lng=scan_center_lng,
        debug=payload["debug"],
    )


@client_bp.route("/heatmap/schedules", methods=["POST"])
@client_login_required
def client_heatmap_schedules():
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
    if not brand:
        abort(404)
    brand = _hydrate_heatmap_brand(db, brand)

    from webapp.heatmap import clean_keyword

    raw_keywords = request.form.get("keywords") or ""
    keywords = []
    seen = set()
    for part in re.split(r"[\n,]+", raw_keywords):
        keyword = (part or "").strip()
        if not keyword:
            continue
        keyword, _ = clean_keyword(keyword)
        normalized = keyword.lower()
        if normalized and normalized not in seen:
            keywords.append(keyword)
            seen.add(normalized)
        if len(keywords) >= 12:
            break

    try:
        radius_miles = max(1.0, min(50.0, float(request.form.get("radius_miles") or 5)))
    except (TypeError, ValueError):
        radius_miles = 5.0
    try:
        grid_size = max(3, min(10, int(request.form.get("grid_size") or 5)))
    except (TypeError, ValueError):
        grid_size = 5
    try:
        day_of_week = max(0, min(6, int(request.form.get("day_of_week") or 0)))
    except (TypeError, ValueError):
        day_of_week = 0

    run_time = (request.form.get("run_time") or "08:00").strip()
    if not re.match(r"^\d{2}:\d{2}$", run_time):
        run_time = "08:00"
    timezone_name = (request.form.get("timezone") or brand.get("sales_bot_appointment_reminder_timezone") or "America/Phoenix").strip()
    provider_preference = (request.form.get("provider_preference") or "google").strip().lower()
    if provider_preference not in {"google", "local_falcon", "auto"}:
        provider_preference = "google"

    business_lat = float(brand.get("business_lat") or 0)
    business_lng = float(brand.get("business_lng") or 0)
    if keywords and business_lat == 0 and business_lng == 0:
        flash("Set the business location before scheduling heatmap scans.", "warning")
        return redirect(url_for("client.client_heatmap"))
    if keywords and not (brand.get("google_place_id") or "").strip():
        flash("Link the Google Place ID before scheduling heatmap scans.", "warning")
        return redirect(url_for("client.client_heatmap"))

    next_run_at = _next_heatmap_run_at(day_of_week, run_time, timezone_name)
    schedules = [
        {
            "keyword": keyword,
            "grid_size": grid_size,
            "radius_miles": radius_miles,
            "center_lat": business_lat,
            "center_lng": business_lng,
            "provider_preference": provider_preference,
            "day_of_week": day_of_week,
            "run_time": run_time,
            "timezone": timezone_name,
            "enabled": True,
            "next_run_at": next_run_at,
        }
        for keyword in keywords
    ]
    db.replace_heatmap_schedules(brand_id, schedules)
    if schedules:
        flash(f"Weekly heatmap scans scheduled for {len(schedules)} keyword{'s' if len(schedules) != 1 else ''}.", "success")
    else:
        flash("Weekly heatmap scans cleared.", "success")
    return redirect(url_for("client.client_heatmap"))


@client_bp.route("/heatmap/test-api", methods=["POST"])
@client_login_required
def client_heatmap_test_api():
    """Quick API key validation: tries a simple Places API call from the server."""
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
    if not brand:
        return jsonify(ok=False, error="Brand not found"), 404
    brand = _hydrate_heatmap_brand(db, brand)

    api_key = _resolve_brand_maps_api_key(db, brand)
    if not api_key:
        return jsonify(ok=False, error="No API key configured."), 400

    import requests as _req
    checks = {}

    # Test 1: Places API (New) Text Search
    try:
        resp = _req.post(
            "https://places.googleapis.com/v1/places:searchText",
            json={"textQuery": "coffee", "maxResultCount": 1},
            headers={
                "X-Goog-Api-Key": api_key,
                "X-Goog-FieldMask": "places.displayName",
                "Content-Type": "application/json",
            },
            timeout=10,
        )
        if resp.status_code == 200:
            checks["places_new"] = {"ok": True, "detail": "Working"}
        else:
            body = resp.text[:300]
            checks["places_new"] = {"ok": False, "detail": f"HTTP {resp.status_code}: {body}"}
    except Exception as exc:
        checks["places_new"] = {"ok": False, "detail": str(exc)}

    # Test 2: Geocoding API
    try:
        resp = _req.get(
            "https://maps.googleapis.com/maps/api/geocode/json",
            params={"address": "New York", "key": api_key},
            timeout=10,
        )
        data = resp.json()
        if data.get("status") == "OK":
            checks["geocoding"] = {"ok": True, "detail": "Working"}
        else:
            checks["geocoding"] = {"ok": False, "detail": data.get("error_message") or data.get("status", "Unknown")}
    except Exception as exc:
        checks["geocoding"] = {"ok": False, "detail": str(exc)}

    # Test 3: Legacy Places Text Search
    try:
        resp = _req.get(
            "https://maps.googleapis.com/maps/api/place/textsearch/json",
            params={"query": "coffee", "key": api_key},
            timeout=10,
        )
        data = resp.json()
        if data.get("status") == "OK":
            checks["places_legacy"] = {"ok": True, "detail": "Working"}
        else:
            checks["places_legacy"] = {"ok": False, "detail": data.get("error_message") or data.get("status", "Unknown")}
    except Exception as exc:
        checks["places_legacy"] = {"ok": False, "detail": str(exc)}

    local_falcon_key = _resolve_local_falcon_api_key(db, brand)
    if local_falcon_key:
        checks["local_falcon"] = {
            "ok": True,
            "detail": "Token saved. Scans retrieve matching saved Local Falcon reports first and fall back to Google rank-only when no report is available.",
        }
    else:
        checks["local_falcon"] = {
            "ok": False,
            "detail": "Not configured. Add a Local Falcon token in Connections to retrieve saved Local Falcon geo-grid reports.",
        }

    all_ok = all(c["ok"] for key, c in checks.items() if key != "local_falcon")
    any_places = checks.get("places_new", {}).get("ok") or checks.get("places_legacy", {}).get("ok")
    return jsonify(ok=True, all_ok=all_ok, any_places=any_places, checks=checks)


@client_bp.route("/heatmap/save-location", methods=["POST"])
@client_login_required
def client_heatmap_save_location():
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
    if not brand:
        return jsonify(ok=False, error="Brand not found"), 404
    brand = _hydrate_heatmap_brand(db, brand)

    data = request.get_json(silent=True) or {}
    address = (data.get("address") or "").strip()

    if not address:
        return jsonify(ok=False, error="Address is required"), 400

    api_key = _resolve_brand_maps_api_key(db, brand)
    if not api_key:
        return jsonify(ok=False, error="Google Maps API key not configured. Add it in Connections."), 400

    from webapp.heatmap import geocode_address
    try:
        result = geocode_address(api_key, address)
    except Exception as exc:
        return jsonify(ok=False, error="Geocoding API error: " + str(exc)), 500
    if not result:
        return jsonify(ok=False, error="Could not geocode that address. Check spelling and try again."), 400

    db.update_brand_number_field(brand_id, "business_lat", result["lat"])
    db.update_brand_number_field(brand_id, "business_lng", result["lng"])

    return jsonify(ok=True, lat=result["lat"], lng=result["lng"],
                   formatted=result["formatted"])


