def _wp_connected(brand):
    return bool(
        (brand.get("wp_site_url") or "").strip()
        and (brand.get("wp_username") or "").strip()
        and (brand.get("wp_app_password") or "").strip()
    )


def _wp_auth_headers(brand, user_agent):
    import base64

    wp_user = (brand.get("wp_username") or "").strip()
    wp_pass = (brand.get("wp_app_password") or "").strip()
    token = base64.b64encode(f"{wp_user}:{wp_pass}".encode()).decode()
    return {
        "Authorization": f"Basic {token}",
        "X-GM-Auth": f"Basic {token}",
        "User-Agent": user_agent,
        "Accept": "application/json",
        "Content-Type": "application/json",
    }


def _wp_browser_json_headers(brand):
    headers = _wp_auth_headers(
        brand,
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 "
        "(KHTML, like Gecko) Chrome/124.0 Safari/537.36",
    )
    headers["Accept"] = "application/json"
    headers["Content-Type"] = "application/json"
    return headers


def _sanitize_wp_post_content(content):
    raw = str(content or "")
    if not raw:
        return ""
    try:
        from bs4 import BeautifulSoup

        soup = BeautifulSoup(raw, "html.parser")
        for tag in soup.find_all(["script", "noscript"]):
            tag.decompose()
        for tag in soup.find_all(True):
            for attr in list(tag.attrs):
                attr_lower = str(attr or "").lower()
                value = tag.attrs.get(attr)
                value_text = " ".join(value) if isinstance(value, list) else str(value or "")
                if attr_lower.startswith("on") or attr_lower in {"srcdoc"} or value_text.strip().lower().startswith("javascript:"):
                    del tag.attrs[attr]
        return str(soup)
    except Exception:
        cleaned = re.sub(r"<\s*(script|noscript)\b[^>]*>.*?<\s*/\s*\1\s*>", "", raw, flags=re.I | re.S)
        cleaned = re.sub(r"\s+on[a-z]+\s*=\s*(['\"]).*?\1", "", cleaned, flags=re.I | re.S)
        cleaned = re.sub(r"\s+on[a-z]+\s*=\s*[^\s>]+", "", cleaned, flags=re.I)
        cleaned = re.sub(r"(href|src)\s*=\s*(['\"])\s*javascript:.*?\2", r"\1=\"#\"", cleaned, flags=re.I | re.S)
        return cleaned


def _wp_publish_delay(seconds=0.35):
    try:
        time.sleep(float(seconds))
    except Exception:
        pass


def _wp_security_challenge_error(status_code, response_text, action_label="Publish"):
    body = (response_text or "")[:500]
    body_lower = body.lower()
    prefix = f"{action_label} failed"
    if "sgcaptcha" in body_lower or "/.well-known/sgcaptcha" in body_lower or (status_code == 202 and "captcha" in body_lower):
        return (
            f"{prefix}: the host returned a CAPTCHA challenge (HTTP 202) before WordPress could process "
            "the publish request. The request is being blocked at the hosting/firewall layer."
        )
    if status_code == 202:
        return (
            f"{prefix}: the site returned HTTP 202 instead of creating the post. This usually means "
            "a server-level security layer (WAF, bot protection, or firewall) intercepted the request before "
            "WordPress could process it."
        )
    if status_code == 401:
        return f"{prefix}: WordPress returned 401. The application password may be expired or the user lacks permission to create posts. Re-enter your app password in Settings, or check that the WordPress user has an Editor/Administrator role."
    if status_code == 403:
        return f"{prefix}: WordPress returned 403 Forbidden. A security plugin or hosting firewall may be blocking REST API access."
    return f"WordPress API error {status_code}: {body[:200]}"


def _wp_should_try_custom_endpoint(status_code, response_text):
    body_lower = (response_text or "").lower()
    if "sgcaptcha" in body_lower or "/.well-known/sgcaptcha" in body_lower or "captcha" in body_lower:
        return True
    if int(status_code or 0) == 400 and any(marker in body_lower for marker in ("acf", "template", "rest_invalid_param")):
        return True
    return int(status_code or 0) in {202, 403, 406, 418, 429}


def _wp_pull_queue_result(message=""):
    return {
        "ok": False,
        "queued_for_pull": True,
        "error": message or (
            "Publish queued for WordPress pull. The site blocks inbound publish requests from GroMore, "
            "so the GroMore WordPress helper plugin must pull and publish this post from WordPress. "
            "Open WordPress > Settings > GroMore Publisher and click Pull Queued Post Now, or wait for the helper's five-minute WP-Cron pull."
        ),
    }


def _site_builder_template_for_build(db, build):
    intake = {}
    if isinstance(build, dict):
        intake = build.get("intake") or {}
        if not intake:
            try:
                intake = json.loads(build.get("intake_json") or "{}")
            except Exception:
                intake = {}
    template_id = int(((intake.get("builder_site_template") or {}).get("id")) or 0)
    if template_id:
        return db.get_sb_site_template(template_id) or {}
    return {}


def _site_builder_source_value(source, *, page, build, brand):
    if isinstance(source, dict):
        if "literal" in source:
            return source.get("literal")
        raw_source = source.get("source") or source.get("path") or ""
        value = _site_builder_source_value(raw_source, page=page, build=build, brand=brand)
        if (value is None or value == "" or value == []) and "fallback" in source:
            value = _site_builder_source_value(source.get("fallback"), page=page, build=build, brand=brand)
        if source.get("as_json") and not isinstance(value, str):
            return json.dumps(value or [], ensure_ascii=True)
        if source.get("join") and isinstance(value, list):
            return str(source.get("join")).join(str(item) for item in value)
        return value
    if isinstance(source, list):
        return [_site_builder_source_value(item, page=page, build=build, brand=brand) for item in source]
    key = str(source or "").strip()
    if not key:
        return ""
    if key.startswith("literal:"):
        return key.split(":", 1)[1]

    intake = {}
    if isinstance(build, dict):
        intake = build.get("intake") or {}
        if not intake:
            try:
                intake = json.loads(build.get("intake_json") or "{}")
            except Exception:
                intake = {}

    page_values = {
        "id": page.get("id"),
        "page_type": page.get("page_type"),
        "label": page.get("label"),
        "slug": page.get("slug"),
        "title": page.get("title"),
        "content": page.get("content"),
        "content_html": page.get("content"),
        "full_html": page.get("full_html") or page.get("content"),
        "excerpt": page.get("excerpt"),
        "seo_title": page.get("seo_title"),
        "seo_description": page.get("seo_description"),
        "primary_keyword": page.get("primary_keyword"),
        "secondary_keywords": page.get("secondary_keywords"),
        "faq_items": page.get("faq_items") or [],
        "schemas": page.get("schemas") or [],
        "schema_json": page.get("schemas") or [],
        "schema_html": page.get("schema_html"),
    }
    if key in page_values:
        return page_values[key]
    if key.startswith("page."):
        return page_values.get(key.split(".", 1)[1], "")
    if key.startswith("brand."):
        return (brand or {}).get(key.split(".", 1)[1], "")
    if key.startswith("intake."):
        return intake.get(key.split(".", 1)[1], "")
    return key


def _site_builder_acf_fields_for_page(page, build, brand, site_template):
    if not site_template or not int(site_template.get("acf_enabled") or 0):
        return {}
    acf_map = site_template.get("acf_field_map") or {}
    if not acf_map:
        try:
            acf_map = json.loads(site_template.get("acf_field_map_json") or "{}")
        except Exception:
            acf_map = {}
    if not isinstance(acf_map, dict):
        return {}

    page_type = str(page.get("page_type") or "").strip()
    page_map = {}
    if isinstance(acf_map.get("default"), dict):
        page_map.update(acf_map.get("default") or {})
    if isinstance(acf_map.get("pages"), dict) and isinstance(acf_map["pages"].get(page_type), dict):
        page_map.update(acf_map["pages"][page_type])
    if isinstance(acf_map.get(page_type), dict):
        page_map.update(acf_map[page_type])
    if not page_map and all(not isinstance(v, dict) for v in acf_map.values()):
        page_map = acf_map

    fields = {}
    for field_name, source in (page_map or {}).items():
        clean_name = str(field_name or "").strip()
        if not clean_name:
            continue
        value = _site_builder_source_value(source, page=page, build=build, brand=brand)
        if value is None:
            continue
        if value == "" and not (isinstance(source, dict) and source.get("allow_empty")):
            continue
        fields[clean_name] = value
    return fields


def _wp_custom_publish_url(brand):
    wp_url = (brand.get("wp_site_url") or "").strip().rstrip("/")
    return f"{wp_url}/wp-json/warren/v1/publish"


def _wp_ajax_publish_url(brand):
    wp_url = (brand.get("wp_site_url") or "").strip().rstrip("/")
    return f"{wp_url}/wp-admin/admin-ajax.php"


def _wp_front_publish_url(brand):
    wp_url = (brand.get("wp_site_url") or "").strip().rstrip("/")
    return f"{wp_url}/?gromore_warren_publish=1"


def _wp_parse_helper_publish_response(resp, action_label):
    if resp.status_code not in (200, 201):
        return {
            "ok": False,
            "error": _wp_security_challenge_error(resp.status_code, resp.text, action_label),
            "missing_endpoint": resp.status_code == 404,
            "blocked_by_waf": _wp_should_try_custom_endpoint(resp.status_code, resp.text),
        }

    try:
        data = resp.json() or {}
    except Exception:
        data = {}
    text = (resp.text or "").strip()
    if not data and text in {"0", "-1"}:
        return {
            "ok": False,
            "error": "GroMore/Warren WordPress helper plugin is not installed or is older than version 1.2.0.",
            "missing_endpoint": True,
            "blocked_by_waf": False,
        }
    if not data:
        return {
            "ok": False,
            "error": "GroMore/Warren WordPress helper endpoint did not return JSON. Install or update the helper plugin.",
            "missing_endpoint": not _wp_should_try_custom_endpoint(resp.status_code, resp.text),
            "blocked_by_waf": _wp_should_try_custom_endpoint(resp.status_code, resp.text),
        }
    if data.get("success") is True and isinstance(data.get("data"), dict):
        data = data["data"]
    if data.get("ok") is False or data.get("success") is False:
        message = ""
        if isinstance(data.get("data"), dict):
            message = data["data"].get("message") or data["data"].get("error") or ""
        return {
            "ok": False,
            "error": str(data.get("error") or data.get("message") or message or f"{action_label} failed.")[:200],
            "missing_endpoint": False,
            "blocked_by_waf": False,
        }

    wp_id = data.get("id") or data.get("wp_post_id") or data.get("wp_page_id") or 0
    wp_url = data.get("link") or data.get("url") or data.get("wp_post_url") or data.get("wp_page_url") or ""
    if not wp_id:
        return {"ok": False, "error": f"{action_label} did not return a post/page id.", "missing_endpoint": False, "blocked_by_waf": False}
    return {"ok": True, "wp_id": wp_id, "wp_url": wp_url}


def _wp_helper_payload_steps(payload):
    item_type = payload.get("type") or "post"
    final_status = (payload.get("status") or "publish").strip().lower()
    if final_status == "published":
        final_status = "publish"
    item_id = int(payload.get("id") or 0)

    if item_id:
        update_payload = dict(payload)
        update_payload["status"] = "draft" if final_status != "draft" else "draft"
        steps = [update_payload]
    else:
        create_payload = {
            "type": item_type,
            "title": payload.get("title") or "Untitled",
            "status": "draft",
        }
        for key in ("slug", "parent", "template"):
            if payload.get(key):
                create_payload[key] = payload[key]
        steps = [create_payload]

        update_payload = {
            "type": item_type,
            "content": payload.get("content") or "",
            "excerpt": payload.get("excerpt") or "",
            "status": "draft",
        }
        for key in ("title", "slug", "parent", "meta", "featured_media", "template", "acf"):
            if payload.get(key):
                update_payload[key] = payload[key]
        steps.append(update_payload)

    if final_status and final_status != "draft":
        steps.append({"type": item_type, "status": final_status})
    return steps


def _publish_via_warren_form_endpoint(brand, payload, endpoint_url, action_name="", helper_label="GroMore helper publish"):
    import json
    import requests as req_lib

    headers = _wp_browser_json_headers(brand)
    headers.pop("Content-Type", None)

    last_result = {}
    item_id = int(payload.get("id") or 0)
    for step_payload in _wp_helper_payload_steps(payload):
        if item_id and not step_payload.get("id"):
            step_payload["id"] = item_id
        form_data = {
            "payload": json.dumps(step_payload),
            "gm_user": (brand.get("wp_username") or "").strip(),
            "gm_app_password": (brand.get("wp_app_password") or "").strip(),
        }
        if action_name:
            form_data["action"] = action_name
        try:
            resp = req_lib.post(
                endpoint_url,
                data=form_data,
                headers=headers,
                timeout=60,
            )
        except Exception as exc:
            return {"ok": False, "error": f"{helper_label} failed: {str(exc)[:160]}", "missing_endpoint": False, "blocked_by_waf": False}

        last_result = _wp_parse_helper_publish_response(resp, helper_label)
        if not last_result.get("ok"):
            return last_result
        item_id = int(last_result.get("wp_id") or item_id or 0)

    return last_result or {"ok": False, "error": f"{helper_label} did not run.", "missing_endpoint": False, "blocked_by_waf": False}


def _publish_via_warren_front_endpoint(brand, payload):
    """Fallback through the normal WordPress front controller, avoiding common blocked publish routes."""
    return _publish_via_warren_form_endpoint(
        brand,
        payload,
        _wp_front_publish_url(brand),
        helper_label="GroMore front publish",
    )


def _publish_via_warren_ajax_endpoint(brand, payload):
    """Fallback for sites where the front helper URL is unavailable but admin-ajax is allowed."""
    return _publish_via_warren_form_endpoint(
        brand,
        payload,
        _wp_ajax_publish_url(brand),
        action_name="gromore_warren_publish",
        helper_label="GroMore AJAX publish",
    )


def _publish_via_warren_wp_endpoint(brand, payload):
    """Optional fallback for sites with a GroMore/Warren mu-plugin installed."""
    import requests as req_lib

    headers = _wp_browser_json_headers(brand)
    try:
        resp = req_lib.post(
            _wp_custom_publish_url(brand),
            json=payload,
            headers=headers,
            timeout=60,
        )
    except Exception as exc:
        return {"ok": False, "error": f"Warren WordPress endpoint failed: {str(exc)[:160]}", "missing_endpoint": False}

    if resp.status_code not in (200, 201):
        missing_endpoint = resp.status_code == 404
        return {
            "ok": False,
            "error": _wp_security_challenge_error(resp.status_code, resp.text, "Warren endpoint publish"),
            "missing_endpoint": missing_endpoint,
        }

    data = resp.json() or {}
    wp_id = data.get("id") or data.get("wp_post_id") or data.get("wp_page_id") or 0
    wp_url = data.get("link") or data.get("url") or data.get("wp_post_url") or data.get("wp_page_url") or ""
    if not wp_id:
        return {"ok": False, "error": "Warren WordPress endpoint did not return a post/page id.", "missing_endpoint": False}
    return {"ok": True, "wp_id": wp_id, "wp_url": wp_url}


def _delete_wp_page(brand, wp_page_id, force=True):
    """Delete a published site-builder page from WordPress."""
    import requests as req_lib

    try:
        page_id = int(wp_page_id or 0)
    except (TypeError, ValueError):
        page_id = 0
    if not page_id:
        return {"ok": True, "deleted": False}

    wp_url = (brand.get("wp_site_url") or "").strip().rstrip("/")
    api_url = f"{wp_url}/wp-json/wp/v2/pages/{page_id}"
    headers = _wp_auth_headers(brand, "GroMore/1.0 (WordPress Site Builder Delete; +https://gromore.com)")
    params = {"force": "true"} if force else None

    try:
        resp = req_lib.delete(api_url, headers=headers, params=params, timeout=30)
        if resp.status_code in (200, 202, 204):
            return {"ok": True, "deleted": True}
        if resp.status_code in (404, 410):
            return {"ok": True, "deleted": False}
        return {"ok": False, "error": f"WordPress API error {resp.status_code}: {resp.text[:200]}"}
    except Exception as exc:
        return {"ok": False, "error": str(exc)[:200]}


def _read_wp_media_source(featured_image_url):
    import mimetypes
    import requests as req_lib

    source = str(featured_image_url or "").strip()
    if not source:
        return {"ok": False, "error": "No featured image source provided."}

    parsed = urlparse(source)
    path = parsed.path or source

    def _content_type_to_extension(content_type):
        guessed = mimetypes.guess_extension((content_type or "").split(";", 1)[0].strip().lower())
        if guessed == ".jpe":
            return ".jpg"
        return guessed or ""

    def _safe_local_read(base_dir, relative_path):
        try:
            root = Path(base_dir).resolve()
            candidate = (root / relative_path).resolve()
            if root != candidate and root not in candidate.parents:
                return None
            if not candidate.exists() or not candidate.is_file():
                return None
            return candidate
        except Exception:
            return None

    local_candidate = None
    if path.startswith("/client/uploads/"):
        rel_path = path.split("/client/uploads/", 1)[1].lstrip("/")
        local_candidate = _safe_local_read(current_app.config.get("UPLOADS_DIR", "data/uploads"), rel_path)
    elif path.startswith("/static/uploads/"):
        rel_path = path.split("/static/", 1)[1].lstrip("/")
        local_candidate = _safe_local_read(current_app.static_folder or "static", rel_path)

    if local_candidate:
        mime_type = mimetypes.guess_type(str(local_candidate.name))[0] or "application/octet-stream"
        return {
            "ok": True,
            "filename": local_candidate.name,
            "content_type": mime_type,
            "bytes": local_candidate.read_bytes(),
        }

    try:
        resp = req_lib.get(source, timeout=30)
    except Exception as exc:
        return {"ok": False, "error": f"Could not fetch featured image: {str(exc)[:160]}"}

    if resp.status_code != 200:
        return {"ok": False, "error": f"Could not fetch featured image: HTTP {resp.status_code}."}

    content_type = (resp.headers.get("Content-Type") or "").split(";", 1)[0].strip().lower()
    if not content_type.startswith("image/"):
        guessed_type = mimetypes.guess_type(path)[0] or ""
        if guessed_type.startswith("image/"):
            content_type = guessed_type
        else:
            return {"ok": False, "error": "Featured image URL did not return an image."}

    filename = Path(parsed.path or "featured-image").name or "featured-image"
    if "." not in filename:
        filename = f"{filename}{_content_type_to_extension(content_type) or '.jpg'}"

    return {
        "ok": True,
        "filename": filename,
        "content_type": content_type,
        "bytes": resp.content,
    }


def _upload_wp_media(brand, featured_image_url):
    import requests as req_lib

    media_source = _read_wp_media_source(featured_image_url)
    if not media_source.get("ok"):
        return media_source

    wp_url = (brand.get("wp_site_url") or "").strip().rstrip("/")
    headers = _wp_browser_json_headers(brand)
    headers.pop("Content-Type", None)
    headers["Content-Type"] = media_source["content_type"]
    headers["Content-Disposition"] = f'attachment; filename="{media_source["filename"]}"'

    try:
        resp = req_lib.post(
            f"{wp_url}/wp-json/wp/v2/media",
            headers=headers,
            data=media_source["bytes"],
            timeout=60,
        )
    except Exception as exc:
        return {"ok": False, "error": f"Featured image upload failed: {str(exc)[:160]}"}

    if resp.status_code not in (200, 201):
        return {"ok": False, "error": f"Featured image upload failed: WordPress API error {resp.status_code}: {resp.text[:200]}"}

    payload = resp.json() or {}
    media_id = payload.get("id")
    if not media_id:
        return {"ok": False, "error": "Featured image upload failed: WordPress did not return a media id."}

    return {
        "ok": True,
        "wp_media_id": media_id,
        "wp_media_url": payload.get("source_url", ""),
    }


def _store_blog_featured_image_upload(file_storage):
    import uuid
    from werkzeug.utils import secure_filename

    if not file_storage or not getattr(file_storage, "filename", ""):
        return {"ok": False, "error": "No image file provided."}

    allowed_ext = {".jpg", ".jpeg", ".png", ".gif", ".webp"}
    ext = Path(file_storage.filename).suffix.lower()
    if ext not in allowed_ext:
        return {"ok": False, "error": f"Featured image type {ext or 'unknown'} is not allowed."}

    try:
        file_storage.stream.seek(0, 2)
        size = file_storage.stream.tell()
        file_storage.stream.seek(0)
    except Exception:
        size = 0
    if size > 10 * 1024 * 1024:
        return {"ok": False, "error": "Featured image is too large. Max 10MB."}

    safe_name = secure_filename(f"blog_featured_{uuid.uuid4().hex}{ext}")
    if not safe_name:
        return {"ok": False, "error": "Could not create a safe filename for the featured image."}

    uploads_dir = Path(current_app.config.get("UPLOADS_DIR", "data/uploads"))
    target_dir = uploads_dir / "blog_featured"
    target_dir.mkdir(parents=True, exist_ok=True)
    target_path = target_dir / safe_name

    try:
        file_storage.save(target_path)
    except Exception as exc:
        current_app.logger.exception("blog featured image upload failed")
        return {"ok": False, "error": f"Featured image upload failed: {str(exc)[:160]}"}

    rel_path = f"blog_featured/{safe_name}".replace("\\", "/")
    return {
        "ok": True,
        "path": rel_path,
        "url": url_for("client.client_serve_upload", filename=rel_path),
    }


def _publish_to_wp(brand, title, content, excerpt="", slug="",
                    seo_title="", seo_description="", categories="",
                    tags="", featured_image_url="", status="publish"):
    """Publish or update a post on WordPress via REST API. Returns dict."""
    import requests as req_lib

    wp_url = brand["wp_site_url"].strip().rstrip("/")

    api_url = f"{wp_url}/wp-json/wp/v2/posts"
    headers = _wp_browser_json_headers(brand)
    sanitized_content = _sanitize_wp_post_content(content)
    final_status = (status or "publish").strip().lower()
    if final_status == "published":
        final_status = "publish"

    create_data = {
        "title": seo_title or title,
        "status": "draft",
    }
    update_data = {
        "content": sanitized_content,
        "excerpt": excerpt,
    }
    if featured_image_url:
        media_result = _upload_wp_media(brand, featured_image_url)
        if not media_result.get("ok"):
            return {"ok": False, "error": media_result.get("error", "Featured image upload failed.")}
        update_data["featured_media"] = media_result["wp_media_id"]
        _wp_publish_delay(0.25)
    if slug:
        create_data["slug"] = slug
    # Yoast SEO fields (if plugin installed)
    meta = {}
    if seo_title:
        meta["_yoast_wpseo_title"] = seo_title
    if seo_description:
        meta["_yoast_wpseo_metadesc"] = seo_description
    if meta:
        update_data["meta"] = meta

    warren_payload = {
        "type": "post",
        "title": create_data["title"],
        "content": sanitized_content,
        "excerpt": excerpt,
        "slug": slug,
        "status": final_status or "draft",
        "meta": meta,
    }
    if update_data.get("featured_media"):
        warren_payload["featured_media"] = update_data["featured_media"]

    def _fallback_or_error(status_code, response_text):
        original_error = _wp_security_challenge_error(status_code, response_text, "Publish")
        if not _wp_should_try_custom_endpoint(status_code, response_text):
            return {"ok": False, "error": original_error}

        custom_result = _publish_via_warren_front_endpoint(brand, warren_payload)
        if not custom_result.get("ok") and custom_result.get("missing_endpoint"):
            custom_result = _publish_via_warren_ajax_endpoint(brand, warren_payload)
        if not custom_result.get("ok") and custom_result.get("missing_endpoint"):
            custom_result = _publish_via_warren_wp_endpoint(brand, warren_payload)
        if custom_result.get("ok"):
            return {
                "ok": True,
                "wp_post_id": custom_result["wp_id"],
                "wp_post_url": custom_result.get("wp_url", ""),
                "wp_media_id": update_data.get("featured_media", 0),
            }

        if custom_result.get("blocked_by_waf"):
            return _wp_pull_queue_result()
        extra = ""
        if custom_result.get("missing_endpoint"):
            extra = " Install or update the GroMore/Warren WordPress helper plugin on this site."
        elif custom_result.get("error"):
            extra = f" GroMore helper fallback also failed: {custom_result['error']}"
        return {"ok": False, "error": f"{original_error}{extra}"}

    try:
        import logging
        _wp_log = logging.getLogger(__name__)

        # Step 1: create a lightweight draft first. This avoids sending the
        # full HTML body in the first REST request, which trips some WAF rules.
        create_resp = req_lib.post(
            api_url,
            json=create_data,
            headers=headers,
            timeout=30,
        )
        if create_resp.status_code not in (200, 201):
            resp_headers = getattr(create_resp, "headers", {}) or {}
            if not isinstance(resp_headers, dict):
                resp_headers = {}
            _wp_log.warning("[WP-PUBLISH:create] status=%d headers=%s body=%s",
                            create_resp.status_code, dict(resp_headers), create_resp.text[:500])
            return _fallback_or_error(create_resp.status_code, create_resp.text)

        wp_post = create_resp.json() or {}
        wp_post_id = int(wp_post.get("id") or 0)
        if not wp_post_id:
            return {"ok": False, "error": "WordPress created a draft but did not return a post id."}
        warren_payload["id"] = wp_post_id

        _wp_publish_delay()

        # Step 2: update the draft with the full body and metadata.
        update_resp = req_lib.post(
            f"{api_url}/{wp_post_id}",
            json=update_data,
            headers=headers,
            timeout=45,
        )
        if update_resp.status_code not in (200, 201):
            resp_headers = getattr(update_resp, "headers", {}) or {}
            if not isinstance(resp_headers, dict):
                resp_headers = {}
            _wp_log.warning("[WP-PUBLISH:update] status=%d headers=%s body=%s",
                            update_resp.status_code, dict(resp_headers), update_resp.text[:500])
            return _fallback_or_error(update_resp.status_code, update_resp.text)

        wp_post = update_resp.json() or wp_post

        if final_status and final_status != "draft":
            _wp_publish_delay()
            publish_resp = req_lib.post(
                f"{api_url}/{wp_post_id}",
                json={"status": final_status},
                headers=headers,
                timeout=30,
            )
            if publish_resp.status_code not in (200, 201):
                resp_headers = getattr(publish_resp, "headers", {}) or {}
                if not isinstance(resp_headers, dict):
                    resp_headers = {}
                _wp_log.warning("[WP-PUBLISH:status] status=%d headers=%s body=%s",
                                publish_resp.status_code, dict(resp_headers), publish_resp.text[:500])
                return _fallback_or_error(publish_resp.status_code, publish_resp.text)
            wp_post = publish_resp.json() or wp_post

        return {
            "ok": True,
            "wp_post_id": wp_post_id,
            "wp_post_url": wp_post.get("link", ""),
            "wp_media_id": update_data.get("featured_media", 0),
        }
    except Exception as e:
        return {"ok": False, "error": str(e)[:200]}


@client_bp.route("/blog")
@client_login_required
def client_blog():
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
    if not brand:
        abort(404)

    wp_ok = _wp_connected(brand)
    posts = db.get_blog_posts(brand_id) if wp_ok else []

    # Check for due scheduled posts and publish them
    if wp_ok:
        due = db.get_due_blog_posts(brand_id)
        for bp in due:
            result = _publish_to_wp(
                brand, bp["title"], bp["content"],
                excerpt=bp.get("excerpt", ""),
                slug=bp.get("slug", ""),
                seo_title=bp.get("seo_title", ""),
                seo_description=bp.get("seo_description", ""),
            )
            if result["ok"]:
                db.update_blog_post(
                    bp["id"], status="published",
                    wp_post_id=result["wp_post_id"],
                    wp_post_url=result["wp_post_url"],
                    published_at=datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
                )
                # Auto-create Facebook promo for the just-published scheduled post
                _create_fb_promo_for_blog(
                    db, brand, brand_id, bp["title"], result["wp_post_url"],
                    excerpt=bp.get("excerpt", ""),
                    featured_image_url=bp.get("featured_image_url", ""),
                )
            else:
                db.update_blog_post(bp["id"], status="wp_pull_queued" if result.get("queued_for_pull") else "failed")
        # Refresh list after publishing
        if due:
            posts = db.get_blog_posts(brand_id)

    return render_template(
        "client/client_blog.html",
        brand=brand,
        posts=posts,
        wp_connected=wp_ok,
        brand_name=session.get("client_brand_name", brand.get("display_name", "")),
    )


