@client_bp.route("/settings/payment-provider/square/connect")
@client_login_required
def client_square_oauth_connect():
    app_id = (current_app.config.get("SQUARE_APP_ID") or "").strip()
    app_secret = (current_app.config.get("SQUARE_APP_SECRET") or "").strip()
    if not app_id or not app_secret:
        flash("Square OAuth app ID and secret are not configured in Admin Settings yet.", "error")
        return redirect(url_for("client.client_settings") + "?square_oauth_missing=1#connection-panel-payments")

    brand_id = int(session["client_brand_id"])
    state = _square_oauth_serializer().dumps({
        "brand_id": brand_id,
        "client_user_id": int(session.get("client_user_id") or 0),
        "nonce": uuid.uuid4().hex,
    })
    params = urlencode({
        "client_id": app_id,
        "response_type": "code",
        "scope": "MERCHANT_PROFILE_READ PAYMENTS_READ",
        "session": "false",
        "state": state,
        "redirect_uri": _square_oauth_callback_url(),
    })
    return redirect(f"https://connect.squareup.com/oauth2/authorize?{params}")


@client_bp.route("/settings/payment-provider/square/callback")
def client_square_oauth_callback():
    db = _get_db()
    error = (request.args.get("error") or "").strip()
    if error:
        flash(f"Square authorization failed: {error}", "error")
        return redirect(url_for("client.client_settings") + "#connection-panel-payments")

    code = (request.args.get("code") or "").strip()
    state = (request.args.get("state") or "").strip()
    try:
        payload = _square_oauth_serializer().loads(state, max_age=30 * 60)
        brand_id = int(payload.get("brand_id") or 0)
    except BadSignature:
        flash("Square authorization state expired or was invalid. Start the connection again.", "error")
        return redirect(url_for("client.client_settings") + "#connection-panel-payments")

    if not code or brand_id <= 0:
        flash("Square did not return a usable authorization code.", "error")
        return redirect(url_for("client.client_settings") + "#connection-panel-payments")

    app_id = (current_app.config.get("SQUARE_APP_ID") or "").strip()
    app_secret = (current_app.config.get("SQUARE_APP_SECRET") or "").strip()
    if not app_id or not app_secret:
        flash("Square OAuth app ID and secret are missing.", "error")
        return redirect(url_for("client.client_settings") + "#connection-panel-payments")

    try:
        resp = requests.post(
            "https://connect.squareup.com/oauth2/token",
            json={
                "client_id": app_id,
                "client_secret": app_secret,
                "code": code,
                "grant_type": "authorization_code",
                "redirect_uri": _square_oauth_callback_url(),
            },
            headers={
                "Accept": "application/json",
                "Content-Type": "application/json",
                "Square-Version": current_app.config.get("SQUARE_API_VERSION", "2026-01-22"),
            },
            timeout=15,
        )
    except requests.RequestException as exc:
        flash(f"Could not reach Square to finish authorization: {str(exc)[:180]}", "error")
        return redirect(url_for("client.client_settings") + "#connection-panel-payments")

    if resp.status_code != 200:
        flash(f"Square returned {resp.status_code} while authorizing: {resp.text[:180]}", "error")
        return redirect(url_for("client.client_settings") + "#connection-panel-payments")

    token_payload = resp.json() or {}
    access_token = (token_payload.get("access_token") or "").strip()
    refresh_token = (token_payload.get("refresh_token") or "").strip()
    if not access_token or not refresh_token:
        flash("Square did not return both access and refresh tokens.", "error")
        return redirect(url_for("client.client_settings") + "#connection-panel-payments")

    db.update_brand_text_field(brand_id, "payment_provider", "square")
    db.update_brand_text_field(brand_id, "payment_api_key", access_token)
    db.update_brand_text_field(brand_id, "payment_refresh_token", refresh_token)
    db.update_brand_text_field(brand_id, "payment_token_expires_at", token_payload.get("expires_at") or "")
    db.update_brand_text_field(brand_id, "payment_merchant_id", token_payload.get("merchant_id") or "")

    brand = db.get_brand(brand_id) or {}
    from webapp.crm_bridge import square_payment_test_connection

    message, test_error = square_payment_test_connection(brand)
    if test_error:
        flash(f"Square connected, but the permission test needs attention: {test_error}", "warning")
    else:
        flash(message or "Square connected. Tokens will refresh automatically.", "success")
    return redirect(url_for("client.client_settings") + "#connection-panel-payments")


@client_bp.route("/settings/payment-provider/square/disconnect", methods=["POST"])
@client_login_required
def client_square_disconnect():
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id) or {}
    token = (brand.get("payment_api_key") or "").strip()
    app_id = (current_app.config.get("SQUARE_APP_ID") or "").strip()
    app_secret = (current_app.config.get("SQUARE_APP_SECRET") or "").strip()
    if token and app_id and app_secret:
        try:
            requests.post(
                "https://connect.squareup.com/oauth2/revoke",
                json={"client_id": app_id, "access_token": token},
                headers={
                    "Authorization": f"Client {app_secret}",
                    "Accept": "application/json",
                    "Content-Type": "application/json",
                    "Square-Version": current_app.config.get("SQUARE_API_VERSION", "2026-01-22"),
                },
                timeout=10,
            )
        except requests.RequestException:
            log.info("Square token revoke failed during disconnect", exc_info=True)
    for field in (
        "payment_api_key", "payment_refresh_token", "payment_token_expires_at",
        "payment_merchant_id", "payment_account_label", "payment_location_id",
        "payment_account_id",
    ):
        db.update_brand_text_field(brand_id, field, "")
    if (brand.get("payment_provider") or "").strip().lower() == "square":
        db.update_brand_text_field(brand_id, "payment_provider", "")
    flash("Square disconnected in WARREN.", "success")
    return redirect(url_for("client.client_settings") + "#connection-panel-payments")


@client_bp.route("/crm/handoff/<int:delivery_id>/retry", methods=["POST"])
@client_login_required
def client_retry_crm_handoff(delivery_id):
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
    if not brand:
        return jsonify(ok=False, error="Brand not found"), 404

    delivery = db.get_crm_push_delivery(delivery_id, brand_id=brand_id)
    if not delivery:
        return jsonify(ok=False, error="CRM handoff delivery not found."), 404
    if (delivery.get("status") or "").strip().lower() != "failed":
        return jsonify(ok=False, error="Only failed CRM handoffs can be retried."), 400

    try:
        lead_data = json.loads(delivery.get("payload_preview") or "{}")
    except Exception:
        lead_data = {}
    if not isinstance(lead_data, dict):
        lead_data = {}

    thread_id = delivery.get("thread_id")
    if (not lead_data or not (lead_data.get("phone") or lead_data.get("email"))) and thread_id:
        thread = db.get_lead_thread(thread_id, brand_id=brand_id)
        if thread:
            from webapp.warren_brain import _build_crm_lead_payload

            lead_data = _build_crm_lead_payload(thread, {"info_collected": {}}, "retry")

    if not lead_data or not (lead_data.get("phone") or lead_data.get("email")):
        return jsonify(ok=False, error="The saved handoff payload is missing phone/email and cannot be retried."), 400

    try:
        from webapp.crm_bridge import push_lead

        success, detail = push_lead(brand, lead_data)
    except Exception as exc:
        success, detail = False, str(exc)

    detail_text = detail.get("message") if isinstance(detail, dict) else str(detail or "")
    response_preview = (
        json.dumps(detail, separators=(",", ":"), sort_keys=True)
        if isinstance(detail, dict)
        else detail_text
    )
    new_delivery_id = db.record_crm_push_delivery(
        brand_id,
        thread_id=thread_id,
        crm_type=(brand.get("crm_type") or "").strip().lower(),
        status="delivered" if success else "failed",
        detail=detail_text[:500],
        lead_name=lead_data.get("name", ""),
        lead_email=lead_data.get("email", ""),
        lead_phone=lead_data.get("phone", ""),
        payload_preview=json.dumps(lead_data or {}, separators=(",", ":"), sort_keys=True),
        response_preview=response_preview[:2000],
        retry_count=int(delivery.get("retry_count") or 0) + 1,
    )
    if thread_id:
        db.add_lead_event(
            brand_id,
            thread_id,
            "crm_push_retry" if success else "crm_push_retry_failed",
            event_value="success" if success else detail_text[:200],
            metadata={
                "source_delivery_id": delivery_id,
                "new_delivery_id": new_delivery_id,
                "crm_type": (brand.get("crm_type") or "").strip().lower(),
                "detail": response_preview[:500],
            },
        )
        if success and isinstance(detail, dict):
            from webapp.warren_brain import _merge_crm_external_ids

            _merge_crm_external_ids(db, brand_id, thread_id, (brand.get("crm_type") or "").strip().lower(), detail)

    if not success:
        return jsonify(ok=False, error=detail_text or "CRM handoff retry failed.", delivery_id=new_delivery_id)
    return jsonify(ok=True, message=detail_text or "CRM handoff retry delivered.", delivery_id=new_delivery_id)


@client_bp.route("/settings/integration/<provider>", methods=["POST"])
@client_login_required
def client_save_external_integration(provider):
    provider = (provider or "").strip().lower()
    provider_def = _INTEGRATION_CATALOG_BY_KEY.get(provider)
    if not provider_def:
        abort(404)

    db = _get_db()
    brand_id = session["client_brand_id"]
    existing = db.get_brand_integration_config(brand_id, provider) or {}
    config = dict(existing.get("config") or {})

    for field in _integration_fields(provider_def):
        key = field["key"]
        value = (request.form.get(key) or "").strip()
        if field.get("secret") and not value:
            continue
        config[key] = value[:2000]

    status = "configured" if _integration_config_is_ready(provider_def, config) else "not_configured"
    db.upsert_brand_integration_config(brand_id, provider, config, status=status)
    flash(f"{provider_def['name']} settings saved.", "success")
    return redirect(url_for("client.client_settings") + "#connection-panel-integration-hub")


