def client_make_incoming_test():
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
    if not brand:
        return jsonify(ok=False, error="Brand not found"), 404

    incoming_secret = (brand.get("sales_bot_incoming_webhook_secret") or "").strip()
    if not incoming_secret:
        return jsonify(ok=False, error="Save an Incoming Lead Webhook Secret before testing Make intake."), 400

    external_id = f"make_test_{uuid.uuid4().hex[:12]}"
    payload = {
        "event_type": "make_connection_test",
        "external_id": external_id,
        "name": "Make Test Lead",
        "email": "make-test@example.com",
        "phone": "+15555550123",
        "source": "make_connection_test",
        "campaign": "Settings test",
        "message": "This is a no-send Warren intake test from the Make.com settings card.",
    }

    from webapp.warren_webhooks import _extract_generic_form_submission, _ingest_lead_submission

    raw_body = json.dumps(payload, separators=(",", ":"), sort_keys=True).encode("utf-8")
    submission = _extract_generic_form_submission(payload, raw_body)
    test_brand = dict(brand)
    test_brand["sales_bot_enabled"] = 0
    thread_id = _ingest_lead_submission(
        db,
        brand_id,
        test_brand,
        external_id=submission["external_id"],
        source=f"incoming_webhook:{submission['source']}",
        lead_name=submission["lead_name"],
        lead_email=submission["lead_email"],
        lead_phone=submission["lead_phone"],
        message_text=submission["message_text"],
        extra_fields=submission["extra_fields"],
        message_header="Make Intake Test",
        allow_auto_send=False,
        automation_event_type="",
    )
    db.record_lead_webhook_delivery(
        brand_id,
        brand_slug=brand.get("slug") or "",
        endpoint=f"/webhooks/leads/{brand.get('slug') or ''}",
        status="accepted",
        http_status=200,
        reason="Make intake test lead added to Warren. No SMS was sent.",
        source=submission["source"],
        lead_name=submission["lead_name"],
        lead_email=submission["lead_email"],
        lead_phone=submission["lead_phone"],
        thread_id=thread_id,
        signature_present=True,
        payload_preview=raw_body.decode("utf-8"),
        remote_addr=request.remote_addr or "",
    )
    return jsonify(ok=True, message=f"Make intake test created Warren lead thread #{thread_id}. No SMS was sent.", thread_id=thread_id)


def _build_client_commercial_payload(thread):
    payload = _normalize_client_commercial_payload(_safe_json_object(thread.get("commercial_data_json")))
    payload["name"] = payload.get("name") or (thread.get("lead_name") or "").strip() or payload.get("business_name") or "Commercial Prospect"
    payload["email"] = (thread.get("lead_email") or "").strip().lower() or payload.get("email") or ""
    payload["phone"] = (thread.get("lead_phone") or "").strip() or payload.get("phone") or ""
    payload["business_name"] = payload.get("business_name") or (thread.get("lead_name") or "").strip() or payload["name"]
    payload["source"] = payload.get("source") or (thread.get("source") or "").strip() or "commercial_prospecting"
    payload["stage"] = payload.get("stage") or (thread.get("status") or "").strip() or "new"
    payload["summary"] = (thread.get("summary") or "").strip() or payload.get("summary") or ""
    return _normalize_client_commercial_payload(payload)


def _build_client_commercial_brief(thread, brand=None):
    from webapp.commercial_strategy import build_commercial_outreach_brief

    payload = _build_client_commercial_payload(thread)
    brief = build_commercial_outreach_brief(payload, brand=brand)
    return payload, _apply_client_commercial_outreach_overrides(payload, brief)


def _get_client_commercial_threads(db, brand_id, limit=60):
    threads = db.get_lead_threads(brand_id, limit=limit)
    brand = db.get_brand(brand_id)
    items = []
    for thread in threads:
        if (thread.get("source") or "") != "commercial_prospecting" and (thread.get("commercial_data_json") or "{}").strip() in {"", "{}"}:
            continue
        payload, brief = _build_client_commercial_brief(thread, brand=brand)
        items.append({
            "thread": thread,
            "payload": payload,
            "brief": brief,
        })
    return items


def _normalize_lead_csv_header(value):
    return re.sub(r"[^a-z0-9]+", "", str(value or "").strip().lower())


def _lead_csv_value(row, *aliases):
    normalized = {
        _normalize_lead_csv_header(key): (value or "").strip()
        for key, value in (row or {}).items()
        if key is not None
    }
    for alias in aliases:
        value = normalized.get(_normalize_lead_csv_header(alias))
        if value:
            return value
    return ""


def _lead_csv_status(value):
    status = (value or "").strip().lower()
    if any(token in status for token in ("won", "customer", "client", "converted", "closed won")):
        return "won"
    if any(token in status for token in ("lost", "dead", "disqualified", "closed lost")):
        return "lost"
    if "book" in status or "appointment" in status:
        return "booked"
    if "qualif" in status:
        return "qualified"
    if "quote" in status:
        return "quoted"
    if any(token in status for token in ("contact", "engaged", "replied", "conversation")):
        return "engaged"
    return "new"


def _import_ghl_lead_csv(db, brand_id, file_storage, row_limit=2000):
    raw = file_storage.read()
    if not raw:
        raise ValueError("The CSV file was empty.")
    try:
        text = raw.decode("utf-8-sig")
    except UnicodeDecodeError:
        text = raw.decode("latin-1")

    reader = csv.DictReader(StringIO(text))
    if not reader.fieldnames:
        raise ValueError("The CSV needs a header row.")

    imported = 0
    skipped = 0
    thread_ids = []

    for index, row in enumerate(reader, start=1):
        if index > row_limit:
            skipped += 1
            continue

        first_name = _lead_csv_value(row, "first name", "first_name", "firstname", "contact first name")
        last_name = _lead_csv_value(row, "last name", "last_name", "lastname", "contact last name")
        full_name = _lead_csv_value(row, "name", "full name", "full_name", "contact name", "contact")
        lead_name = full_name or " ".join(part for part in (first_name, last_name) if part).strip()
        email = _lead_csv_value(row, "email", "email address", "email_address", "contact email").lower()
        phone = _normalize_client_phone_number(_lead_csv_value(
            row,
            "phone",
            "phone number",
            "mobile",
            "mobile phone",
            "cell phone",
            "contact phone",
        ))
        if not any((lead_name, email, phone)):
            skipped += 1
            continue

        ghl_id = _lead_csv_value(row, "id", "contact id", "contact_id", "ghl id", "go high level id")
        source = _lead_csv_value(row, "source", "lead source", "utm source") or "ghl_csv_import"
        original_status = _lead_csv_value(row, "status", "stage", "pipeline stage", "opportunity status")
        service_needed = _lead_csv_value(row, "service", "service needed", "interested in", "tags")
        notes = _lead_csv_value(row, "notes", "note", "message", "description")
        address = _lead_csv_value(row, "address", "street address", "address1", "full address")
        city = _lead_csv_value(row, "city")
        state = _lead_csv_value(row, "state", "province")
        postal_code = _lead_csv_value(row, "zip", "zip code", "postal code")

        identity = ghl_id or email or phone or lead_name
        external_thread_id = "ghl_csv:" + uuid.uuid5(
            uuid.NAMESPACE_URL,
            f"{brand_id}:{identity}".lower(),
        ).hex

        summary_parts = ["Imported from GoHighLevel CSV"]
        if original_status:
            summary_parts.append(f"Original status: {original_status}")
        if service_needed:
            summary_parts.append(f"Interest: {service_needed}")
        if notes:
            summary_parts.append(notes[:500])

        import_payload = {
            "source_details_json": {
                "import_type": "ghl_csv",
                "source": source,
                "ghl_id": ghl_id,
                "original_status": original_status,
                "row_number": index,
            },
            "service_needed": service_needed,
            "service_address": address,
            "city": city,
            "state": state,
            "postal_code": postal_code,
            "notes": notes,
        }
        thread_id = db.upsert_lead_thread(
            brand_id,
            "lead_form",
            external_thread_id,
            {
                "lead_name": lead_name,
                "lead_email": email,
                "lead_phone": phone,
                "source": "ghl_csv_import",
                "status": _lead_csv_status(original_status),
                "summary": " | ".join(part for part in summary_parts if part),
                "commercial_data_json": json.dumps(import_payload),
            },
        )
        if not db.get_lead_events(brand_id, thread_id, event_type="ghl_csv_imported", limit=1):
            db.add_lead_message(
                thread_id,
                "inbound",
                "system",
                "Lead imported from GoHighLevel CSV.",
                channel="lead_form",
                external_message_id=f"{external_thread_id}:import",
                metadata={"source": "ghl_csv_import", "row_number": index},
            )
            db.add_lead_event(
                brand_id,
                thread_id,
                "ghl_csv_imported",
                email or phone or lead_name,
                {"row_number": index, "source": source, "original_status": original_status},
            )
        imported += 1
        thread_ids.append(thread_id)

    return {"imported": imported, "skipped": skipped, "thread_ids": thread_ids}


@client_bp.route("/crm")
@client_login_required
def client_crm():
    db = _get_db()
    brand_id = session["client_brand_id"]
    brand = db.get_brand(brand_id)
